import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const feministSocialContinuationPhilosopherArticles:Record<string,ArticleSection[]>={
  'mary-astell':[
    section('overview','Rational freedom in a world that denied women education',[
      `Mary Astell is one of the most important early modern philosophers of women's education, marriage, and rational agency. She wrote in late seventeenth- and early eighteenth-century England, when women were usually denied university training, legal independence after marriage, and public authority as intellectual equals. Her philosophical originality lies in taking claims about reason, soul, freedom, and Christian moral responsibility seriously enough to ask why they were not applied to women.`,
      `Astell matters because she turns the rationalist language of the period against patriarchal custom. If women have rational souls, then keeping them ignorant is not a harmless social arrangement; it is a moral and political injury. If marriage is a voluntary relation, then a marriage arranged through ignorance, dependence, or vanity is not genuine freedom. Her work is not simply a demand for access to polite learning. It is an argument that women cannot be responsible moral agents unless society gives them the conditions for disciplined judgment.`
    ],['feminist-philosophy','political-philosophy','rationalism'],['mary-astell','descartes','locke','wollstonecraft'],['A Serious Proposal to the Ladies','Some Reflections upon Marriage']),
    section('historical-setting','Restoration England, Anglican politics, and learned exclusion',[
      `Astell lived after the English Civil War and Restoration, in a society still shaped by disputes over church, monarchy, toleration, education, and household authority. Learned women existed, but they had to work through private study, patronage, correspondence, religious writing, and print genres that were not always treated as philosophy. The household was often defended as a miniature political order, with male authority presented as natural, religious, or socially necessary.`,
      `That setting explains the sharpness of Astell's questions. She is not writing from a modern secular university or from a movement with stable political rights. She writes as an Anglican thinker who accepts many religious and social assumptions of her world while exposing their contradictions. Her feminism is therefore historically specific: conservative in some political loyalties, radical in its insistence that women's rational and spiritual capacities make their subordination indefensible.`
    ],['feminist-philosophy','political-philosophy','philosophy-of-religion'],['mary-astell','locke'],['A Serious Proposal to the Ladies']),
    section('life-and-works','A life of study, friendship, and public argument',[
      `Astell was born in Newcastle in 1666 and later moved to London, where she entered circles of educated women, religious writers, and patrons. She did not build a philosophy through a university office or a formal school. Her work appeared in proposals, polemics, devotional writing, and political-religious argument. That mixed literary form matters because it shows how women philosophers often had to write across accepted categories rather than inside institutions designed for them.`,
      `Her most famous texts are A Serious Proposal to the Ladies and Some Reflections upon Marriage. The first proposes a community of female study and religious discipline; the second criticizes the conditions under which marriage can become domination disguised as duty. The Christian Religion, as Profess'd by a Daughter of the Church of England presents a more explicitly theological and philosophical defense of faith, reason, and moral responsibility. Together these works show Astell as more than a single-issue pamphleteer.`
    ],['feminist-philosophy','philosophy-of-religion'],['mary-astell'],['A Serious Proposal to the Ladies','Some Reflections upon Marriage','The Christian Religion']),
    section('central-question','Can a rational soul be kept dependent without contradiction?',[
      `Astell's central question is simple enough for beginners and devastating enough for political philosophy: if women are rational souls answerable to God and capable of virtue, how can society justify training them for dependence, vanity, and obedience rather than judgment? She does not merely say that some individual men behave badly. She asks whether the practices of education, courtship, marriage, and reputation form women into the very weakness later used to rationalize their exclusion.`,
      `This question exposes a circular argument. Women are denied serious education because they are said to be frivolous; then they are trained for ornament, flattery, and dependence; then their socially produced habits are used as evidence that they were naturally unfit for serious study. Astell's philosophical move is to break that circle. Capacity must be judged under fair conditions of cultivation, not under conditions designed to prevent its development.`
    ],['feminist-philosophy','epistemology','political-philosophy'],['mary-astell','wollstonecraft'],['A Serious Proposal to the Ladies']),
    section('education','Education as moral and intellectual liberation',[
      `A Serious Proposal to the Ladies argues that women need a serious education oriented toward reason, virtue, self-knowledge, and religious discipline. Astell imagines a female academy or religious retirement where women could study without the pressures of courtship and fashion. The proposal is not a modern university plan, but it is a bold institutional response to a philosophical problem: rational beings need environments that let reason become active and stable.`,
      `Education, for Astell, is not decorative accomplishment. It is a remedy for distorted desire. If women are trained to value admiration, beauty, and marriage prospects above truth and virtue, their agency is damaged before they make adult choices. Learning helps them distinguish appearance from worth, flattery from respect, and custom from reason. In this sense, Astell links epistemology to freedom. One cannot choose well if one's attention has been systematically miseducated.`
    ],['feminist-philosophy','epistemology','ethics'],['mary-astell','wollstonecraft'],['A Serious Proposal to the Ladies']),
    section('marriage','Marriage, consent, and domestic power',[
      `Some Reflections upon Marriage is Astell's most famous intervention in political and social philosophy. She does not simply condemn marriage as such. She asks what marriage becomes when women are pressured into it through economic dependence, inadequate education, romantic fantasy, family ambition, and social fear. A choice made under such conditions may look voluntary while failing to express genuine rational freedom.`,
      `Her analysis turns the household into a site of political thought. If a woman enters marriage without preparation, property, education, or realistic knowledge of power, then obedience can become servitude. Astell compares the rhetoric of political liberty with the toleration of domestic subordination. The result is an early feminist challenge to theories that defend freedom in public while leaving hierarchy in the home nearly untouched.`
    ],['feminist-philosophy','political-philosophy','ethics'],['mary-astell','locke','wollstonecraft'],['Some Reflections upon Marriage']),
    section('reason-and-religion','Reason, faith, and the discipline of self-command',[
      `Astell's feminism is inseparable from her religious philosophy. She believes the soul is made for truth and moral improvement, and she treats reason as a divine gift that should govern appetite, pride, and social vanity. This means that women's education is not only a matter of fairness; it is part of their vocation as creatures responsible for knowing and loving the good.`,
      `Modern readers sometimes expect feminist philosophy to reject religious authority, but Astell shows a different path. She uses Anglican moral theology and rationalist metaphysics to criticize social arrangements that stunt women. Her piety is not passive submission to every existing hierarchy. It is a standard against which customs can be judged. If a practice prevents rational and spiritual growth, it cannot be defended merely because it is old or convenient.`
    ],['philosophy-of-religion','feminist-philosophy','ethics'],['mary-astell','descartes'],['The Christian Religion','A Serious Proposal to the Ladies']),
    section('relations-to-rationalism','Cartesian inheritance without simple imitation',[
      `Astell is often read in relation to Cartesian and rationalist philosophy because she emphasizes the immaterial soul, clear thought, self-examination, and the governance of passion by reason. She does not simply repeat Descartes. She adapts rationalist themes to problems that Descartes did not center: women's education, gendered dependence, and the social conditions of rational agency. The result is an early modern feminist use of metaphysics and epistemology.`,
      `This relation matters because it prevents a narrow history of rationalism. If rationalism is only the story of Descartes, Spinoza, and Leibniz, then the social and gendered implications of rational agency are easy to miss. Astell asks what rationalism means when the rational soul belongs to a woman whose society treats her as ornamental, dependent, or naturally inferior. She makes the abstract dignity of reason institutionally concrete.`
    ],['rationalism','feminist-philosophy','metaphysics'],['mary-astell','descartes','anne-conway'],['A Serious Proposal to the Ladies','The Christian Religion']),
    section('influence','Astell, Wollstonecraft, and feminist political thought',[
      `Astell's direct influence is complex, but she clearly belongs to the genealogy of feminist political thought that later includes Mary Wollstonecraft. Both thinkers argue that women's apparent weakness is produced by education and social expectation. Both criticize marriage when it rests on dependency and vanity. Both connect reason to freedom. Their differences are also important: Astell's religious and political commitments are not Wollstonecraft's republican Enlightenment language.`,
      `Reading them together shows that feminist philosophy did not begin in one moment or one ideological package. It emerged through repeated pressure on the gap between universal claims and selective application. Astell asks why rational souls are denied cultivation; Wollstonecraft asks why rights and virtue are denied to women; later feminist philosophers ask how gender, race, class, sexuality, and institutions shape agency. Astell is an early, demanding voice in that continuing argument.`
    ],['feminist-philosophy','political-philosophy'],['mary-astell','wollstonecraft'],['A Serious Proposal to the Ladies','A Vindication of the Rights of Woman']),
    section('controversies','Conservative radicalism and interpretive tension',[
      `Astell can be difficult to place because she combines arguments that sound radically feminist with political and religious commitments that can sound conservative. She criticizes domination in marriage yet does not simply embrace democratic or egalitarian politics across the board. She defends women's reason while remaining committed to Anglican orthodoxy and social order. This mixture should not be treated as hypocrisy too quickly. It reflects the available intellectual languages and loyalties of her setting.`,
      `The interpretive tension is philosophically productive. Astell shows that feminist arguments can arise from within traditions often assumed to be only restrictive. She also shows the limits of such arguments when they do not fully generalize their own critique of domination. Beginners should avoid making her either a modern liberal in disguise or merely a conservative writer with a few proto-feminist lines. The power of her work lies in the unstable combination.`
    ],['feminist-philosophy','political-philosophy','philosophy-of-religion'],['mary-astell','wollstonecraft'],['Some Reflections upon Marriage']),
    section('branch-connections','How Astell connects branches of philosophy',[
      `Astell is a useful bridge between feminist philosophy, epistemology, political philosophy, and philosophy of religion. Her argument about women is not only a claim about social fairness; it depends on a view of the mind as capable of truth and self-command. That makes bad education epistemically damaging. It does not merely withhold information. It forms habits of attention that make people less able to distinguish reason from fashion, flattery, or fear.`,
      `She also shows that political philosophy cannot stop at parliaments, contracts, and sovereigns. Domestic life contains authority, dependence, consent, and coercion. A woman who has been trained for ignorance and economic vulnerability may formally choose marriage while lacking the conditions of free choice. That analysis connects Astell to later feminist questions about structural power. Her religious language can seem distant, but the philosophical pattern remains familiar: agency requires institutions that cultivate the capacities they claim to respect.`
    ],['feminist-philosophy','epistemology','political-philosophy'],['mary-astell','wollstonecraft','locke'],['A Serious Proposal to the Ladies','Some Reflections upon Marriage']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is that Astell is important only because she anticipated later feminism. That framing makes her valuable only as a step toward someone else. She is better read as a philosopher with her own questions about rational agency, religious vocation, education, and domestic power. Another misunderstanding is that her proposal for female retirement is escapist. It is also an institutional experiment in creating the conditions for freedom.`,
      `A third misunderstanding is to treat her religious commitments as automatically opposed to her feminist arguments. In Astell's own thought, faith and reason support the claim that women are morally responsible beings, not decorative dependents. A fourth error is to assume that criticizing marriage means rejecting all intimate life. Astell criticizes marriage formed by ignorance, pressure, and domination. Her deeper concern is whether a relationship can respect rational and spiritual equality.`
    ],['feminist-philosophy','ethics'],['mary-astell'],['A Serious Proposal to the Ladies','Some Reflections upon Marriage']),
    section('reading-strategy','How to read Astell',[
      `Begin with selections from A Serious Proposal to the Ladies, especially the argument that women need serious intellectual and moral education. Then read Some Reflections upon Marriage, watching how Astell moves from social observation to philosophical criticism of consent, dependence, and authority. After that, read portions of The Christian Religion to see how her theological commitments connect with her account of reason and moral agency.`,
      `A good reading question is: what must be true about education for choice to count as free? That question keeps Astell from becoming only a historical curiosity. It also links her to contemporary debates about socialization, autonomy, religious identity, and structural injustice. Her prose can feel polemical, but behind the polemic is a precise philosophical claim: rational beings cannot flourish when their society trains them not to use reason well.`,
      `It is also useful to read Astell beside Locke and Wollstonecraft. Locke helps reveal why consent language can leave domestic power underexamined. Wollstonecraft shows how Astell's concern with education becomes a broader revolutionary argument about citizenship and virtue. The comparison makes Astell's historical specificity clearer: she is not simply ahead of her time, but working within Anglican, rationalist, and gendered assumptions to expose a contradiction those assumptions could not easily contain.`
    ],['feminist-philosophy','political-philosophy','philosophy-of-religion'],['mary-astell','wollstonecraft'],['A Serious Proposal to the Ladies','Some Reflections upon Marriage','The Christian Religion'])
  ],
  'anne-conway':[
    section('overview','A vitalist metaphysics against dead mechanism',[
      `Anne Conway is a major early modern metaphysician whose work challenges the idea that the period was dominated only by male rationalists and empiricists. Her Principles of the Most Ancient and Modern Philosophy develops a living, spiritual, anti-Cartesian account of reality. She rejects a sharp division between inert matter and immaterial mind, arguing instead for a graded universe of created substances capable of transformation.`,
      `Conway matters because she treats metaphysics as a way to repair philosophical pictures that make mind, body, life, suffering, and divine justice unintelligible. Cartesian dualism makes mind and matter so different that their relation becomes puzzling. Strict material mechanism can make living beings look like machines. Conway offers a more continuous universe in which creatures are dynamic, perceptive, and morally ordered. Her system is speculative, but it directly confronts problems that shaped modern philosophy of mind and metaphysics.`
    ],['metaphysics','philosophy-of-mind','rationalism'],['anne-conway','descartes','leibniz','spinoza'],['Principles of the Most Ancient and Modern Philosophy']),
    section('historical-setting','Women, correspondence, and early modern metaphysical debate',[
      `Conway lived in seventeenth-century England, a world of intense debate over mechanism, Platonism, Cartesian philosophy, medicine, religious dissent, and the relation between ancient wisdom and modern science. Women were largely excluded from universities, but learned women participated through private education, correspondence, salons, translation, patronage, and household intellectual circles. Conway's access to philosophical discussion came partly through networks around Henry More and other Cambridge Platonists.`,
      `Her health was fragile, and her life was marked by chronic pain, religious searching, and intellectual exchange. These biographical details should be handled carefully; they do not explain away her philosophy. They do help illuminate why questions about embodiment, suffering, transformation, and divine goodness are urgent in her system. Conway writes metaphysics as someone for whom mind-body relations are not an abstract puzzle only. They are part of the lived problem of what creatures are.`
    ],['metaphysics','philosophy-of-religion'],['anne-conway'],['Principles of the Most Ancient and Modern Philosophy']),
    section('life-and-text','A posthumous book with a complicated transmission',[
      `Conway's main philosophical work, Principles of the Most Ancient and Modern Philosophy, was published after her death. The text has a complicated history of composition, translation, and editorial mediation, which means readers should be cautious about treating every formulation as if it were a polished authorial system. Still, the work presents a coherent and distinctive metaphysical vision that cannot be reduced to the men around her.`,
      `She engaged with Cartesianism, Cambridge Platonism, Kabbalistic themes as mediated through early modern sources, and debates over substance, spirit, and matter. Her relation to Francis Mercury van Helmont and Henry More was important, but it should not make her a passive receiver. Conway's system has its own philosophical pressure: it tries to explain how creatures can be distinct from God, alive rather than inert, morally transformed rather than fixed, and continuous across mind and body.`
    ],['metaphysics','philosophy-of-religion','rationalism'],['anne-conway'],['Principles of the Most Ancient and Modern Philosophy']),
    section('central-question','How can created reality be alive, ordered, and transformable?',[
      `Conway's central question is how to understand created beings without splitting reality into mutually alien substances. If matter is completely dead and mind is completely immaterial, then embodied life becomes mysterious. If everything is only extended matter moved mechanically, then perception, moral development, and spiritual transformation seem flattened. Conway wants a metaphysics in which creatures are real, active, and capable of change without becoming identical with God.`,
      `This question pushes her toward a universe of living created substance. Creatures differ by degrees of spiritual refinement and bodily expression rather than by an absolute gulf between mind and matter. The universe is not a machine assembled from lifeless parts. It is an ordered, dynamic creation in which life, perception, and moral transformation are basic. That picture lets Conway criticize both dualism and crude materialism while preserving divine transcendence.`
    ],['metaphysics','philosophy-of-mind','philosophy-of-religion'],['anne-conway','descartes','spinoza'],['Principles of the Most Ancient and Modern Philosophy']),
    section('anti-cartesianism','Critique of Cartesian dualism',[
      `Conway's critique of Cartesian dualism begins with the sharp opposition between thinking substance and extended substance. Descartes makes mind and body distinct in a way that secures the independence of thought, but the cost is severe. How do such different substances interact? How can living bodies be understood as more than machines? How can embodied suffering and perception fit into a system where matter is essentially inert extension?`,
      `Conway rejects the idea that matter is dead stuff whose nature is exhausted by extension. She also resists making mind a separate kind of created substance wholly unlike body. Her alternative is not simple materialism. It is a vitalist continuity in which created beings have bodily and spiritual aspects, and in which degrees of life and perception pervade creation. This allows her to preserve difference without making the relation between mind and body unintelligible.`
    ],['metaphysics','philosophy-of-mind','rationalism'],['anne-conway','descartes'],['Principles of the Most Ancient and Modern Philosophy','Meditations']),
    section('substance-and-creatures','God, Christ, and created substances',[
      `Conway's metaphysics distinguishes God, Christ or the mediating divine principle in her system, and creatures. God is immutable, perfectly good, and the source of all. Created beings are not parts of God in a simple pantheistic sense, but they depend on God and participate in a living order. The mediating role of Christ helps Conway explain how immutable divinity relates to mutable creatures without collapsing the difference.`,
      `The details are complex and historically shaped by religious sources unfamiliar to many beginners. The philosophical point is clearer: Conway wants a chain of being that allows communication between divine perfection and created change. If God were utterly disconnected from creation, divine goodness and providence would become hard to understand. If creation were simply identical with God, creaturely evil and change would threaten divine immutability. Her mediating structure tries to avoid both problems.`
    ],['metaphysics','philosophy-of-religion'],['anne-conway','spinoza','leibniz'],['Principles of the Most Ancient and Modern Philosophy']),
    section('monads-and-leibniz','Conway, Leibniz, and living individuals',[
      `Conway is often discussed in relation to Leibniz because both reject dead matter and imagine reality through active, perception-like individuals rather than inert blocks. The historical relation is debated, but there are plausible channels through which Conway's ideas may have influenced or paralleled Leibniz's development. It is safest to say that her work belongs to the same broader early modern effort to rethink substance, life, and activity beyond crude mechanism.`,
      `The comparison helps beginners see her originality. Leibniz's monads are windowless centers of perception coordinated by pre-established harmony. Conway's created beings are transformable within a moral and spiritual order. Both refuse to make matter ultimately dead; both seek a metaphysics of activity. Conway's account, however, is more explicitly tied to creaturely improvement, divine justice, and the continuity of spiritual and bodily life.`
    ],['metaphysics','rationalism','philosophy-of-mind'],['anne-conway','leibniz'],['Principles of the Most Ancient and Modern Philosophy','Monadology']),
    section('evil-suffering-transformation','Evil, suffering, and moral transformation',[
      `Conway's metaphysics is also a response to the problem of evil. If God is perfectly good, how should one understand suffering, disorder, and creaturely wrongdoing? She does not treat evil as an equal metaphysical principle opposed to God. Instead, created beings can fall into lower conditions and undergo painful processes that are connected, in her system, to correction and transformation. This is not a simple or emotionally easy answer.`,
      `The philosophical importance lies in her refusal to separate metaphysics from moral life. What creatures are must explain how they can improve, suffer, be restored, and remain within a just order. Modern readers may reject parts of the theodicy, especially where suffering is interpreted through correction. Still, Conway forces a serious question: can a metaphysics of life and transformation make better sense of moral development than a universe of inert matter and disconnected souls?`
    ],['metaphysics','philosophy-of-religion','ethics'],['anne-conway'],['Principles of the Most Ancient and Modern Philosophy']),
    section('feminist-significance','Why Conway matters for feminist history of philosophy',[
      `Conway's feminist significance is not that she wrote an explicitly political manifesto about women's rights. It is that her existence and work challenge the way the canon was built. She was a woman producing serious metaphysics in a period when women were usually treated as outside philosophical authority. Recovering Conway changes the map of early modern thought: the debate over substance, mind, body, and life included women who were not merely correspondents or muses.`,
      `This matters for philosophy itself. Excluding women philosophers does not only create an unfair list of names; it distorts the problems and options available to students. Conway introduces a distinctive alternative to Cartesian dualism, material mechanism, and some forms of rationalist substance theory. Her recovery shows that the history of metaphysics was more experimental, religiously varied, and socially complicated than standard survey courses often suggest.`
    ],['feminist-philosophy','metaphysics'],['anne-conway','mary-astell'],['Principles of the Most Ancient and Modern Philosophy']),
    section('controversies','Speculation, sources, and caution',[
      `Conway's system contains elements that can feel strange to readers trained by later analytic or scientific standards: spiritual hierarchies, transformation of creatures, mediating divine principles, and arguments from theological premises. The temptation is either to dismiss the whole system as obsolete speculation or to romanticize it as a lost holistic wisdom. Both reactions are too quick. Early modern metaphysics was often speculative because the basic categories of matter, life, force, and mind were still being contested.`,
      `Scholars also debate the influence of Kabbalistic material, the role of van Helmont, the extent of Conway's influence on Leibniz, and the best way to understand her relation to Cambridge Platonism. These debates are not side issues. They affect how we place her in the history of philosophy. A cautious reader can acknowledge uncertainty about transmission while still recognizing the philosophical force of the published system.`
    ],['metaphysics','philosophy-of-religion'],['anne-conway','leibniz'],['Principles of the Most Ancient and Modern Philosophy']),
    section('branch-connections','Why Conway belongs in several philosophical maps',[
      `Conway belongs in metaphysics because she offers an account of substance, creaturely dependence, continuity, and change. She belongs in philosophy of mind because her critique of dead matter and sharp dualism reopens the problem of how perception and embodiment belong together. She belongs in philosophy of religion because divine goodness, mediation, evil, and creaturely transformation are central to the system. Treating her under only one label makes the work smaller than it is.`,
      `She is also important for feminist philosophy, even though Principles is not mainly a feminist political text. Canon formation often made metaphysics look like a conversation among men while assigning women to moral, devotional, or educational writing. Conway breaks that pattern. Her recovery changes the content of early modern philosophy, not only its demographics. Students who read her after Descartes, Spinoza, and Leibniz can see that the period contained more than dualism, monism, and monads in the usual sequence.`
    ],['metaphysics','philosophy-of-mind','feminist-philosophy'],['anne-conway','descartes','spinoza','leibniz'],['Principles of the Most Ancient and Modern Philosophy']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is to call Conway simply a mystic and stop there. Her work is religious and speculative, but it also contains precise arguments against dualism, dead matter, and metaphysical discontinuity. Another misunderstanding is to treat her as important only because she may have influenced Leibniz. That question matters, but it should not make her value derivative. Her system is worth reading on its own terms.`,
      `A third mistake is to assimilate her to Spinoza because both resist simple dualism. Conway does not identify God and nature in Spinoza's way. She preserves a creator-creature distinction and a strongly moralized order of transformation. A fourth mistake is to assume that early modern women philosophers only wrote about education or gender. Conway reminds us that women were also active in the hardest metaphysical arguments of the period.`
    ],['metaphysics','feminist-philosophy'],['anne-conway','spinoza','leibniz'],['Principles of the Most Ancient and Modern Philosophy']),
    section('reading-strategy','How to read Conway',[
      `Begin by reading a short account of Cartesian dualism and early modern mechanism, because Conway is easiest to understand as a critic of those pictures. Then read Principles of the Most Ancient and Modern Philosophy slowly, tracking three distinctions: God and creatures, spirit and body, and higher and lower degrees of life. Do not expect the text to look like a modern journal article. Its argument is systematic but historically distant.`,
      `A useful question is: what happens if matter is not dead? That question opens the whole system. It explains her critique of Descartes, her interest in living substance, her account of transformation, and her importance for later debates about mind and body. Read Conway beside Descartes and Leibniz, but also beside Mary Astell, because together they show how early modern women used metaphysics, religion, and reason to make philosophy wider than the inherited canon.`,
      `Then ask why Conway's metaphysics is morally charged. Her living universe is not only an alternative physics of spirit and body. It is a way to defend divine goodness, creaturely improvement, and continuity between suffering and transformation. That does not require accepting every speculative claim. It means reading her as a philosopher who thinks ontology must be able to explain life, pain, responsibility, and hope together.`
    ],['metaphysics','philosophy-of-mind','rationalism'],['anne-conway','descartes','leibniz','mary-astell'],['Principles of the Most Ancient and Modern Philosophy','Meditations','Monadology'])
  ],
  'montesquieu':[
    section('overview','Law, liberty, and the conditions of political life',[
      `Montesquieu is a central Enlightenment political philosopher because he studies laws as parts of whole social worlds. He is famous for the separation of powers, but his project is broader: to understand how forms of government, climate, commerce, religion, manners, history, and institutions interact. The Spirit of the Laws does not offer a single blueprint for all peoples. It asks what makes laws fitting, moderate, oppressive, stable, or corrupt under different conditions.`,
      `His importance lies in comparative political judgment. Hobbes had emphasized security and sovereign authority; Locke had emphasized rights, property, and limited government; Rousseau would emphasize popular sovereignty and civic freedom. Montesquieu asks how liberty can be preserved through institutional arrangement and social moderation. Political philosophy becomes less like deriving one perfect constitution and more like diagnosing the conditions under which power can be restrained.`
    ],['political-philosophy','ethics'],['montesquieu','hobbes','locke','rousseau'],['The Spirit of the Laws']),
    section('historical-setting','France, empire, commerce, and Enlightenment comparison',[
      `Montesquieu wrote in eighteenth-century France, under monarchy, censorship, aristocratic privilege, colonial expansion, commercial growth, and intense debate over ancient and modern politics. European thinkers were reading travel literature, comparing legal systems, and asking whether universal reason could understand diverse customs. This context shaped both the promise and the danger of comparative political theory: it could challenge parochialism, but it could also reproduce stereotypes.`,
      `The Persian Letters uses fictional foreign observers to make French society appear strange to itself. The Spirit of the Laws turns comparison into a massive political inquiry. Montesquieu is not free of the limitations of his age, especially in some claims about climate and peoples. Still, he helped make institutions and social context central to political explanation. Laws, for him, cannot be understood apart from the lives they organize.`
    ],['political-philosophy'],['montesquieu','rousseau'],['Persian Letters','The Spirit of the Laws']),
    section('life-and-works','From satire to institutional analysis',[
      `Charles-Louis de Secondat, Baron de Montesquieu, was born in 1689 into the French nobility and held legal office before turning fully to writing and study. His background gave him close knowledge of law, privilege, and institutional life. Persian Letters made his reputation through satire, religious criticism, and social observation. The later Considerations on the Romans examined historical greatness and decline. The Spirit of the Laws became his major philosophical achievement.`,
      `These works should be read together because they show a development from satire to historical and comparative analysis. Montesquieu is alert to the gap between how societies describe themselves and how power actually operates. He studies not only statutes, but also habits, ambitions, fears, honors, and economic relations. That breadth can make the work sprawling, yet it is part of the point. Political order is not a machine with one lever.`
    ],['political-philosophy'],['montesquieu'],['Persian Letters','Considerations on the Causes of the Greatness of the Romans and their Decline','The Spirit of the Laws']),
    section('central-question','How can power be arranged so liberty survives?',[
      `Montesquieu's central question is how political power can be limited without destroying order. He does not assume that virtue alone will restrain rulers or citizens. Nor does he think law is simply the command of whoever holds authority. Power tends to expand when it is unchecked, and liberty requires arrangements that prevent any one person or body from controlling everything. Institutional design is therefore a moral and political necessity.`,
      `For Montesquieu, liberty is not doing whatever one wants. Political liberty is security under law, especially the confidence that one will not be subject to arbitrary power. This makes legal procedure, judicial independence, intermediate bodies, and balanced authority crucial. A society can call itself free while leaving people exposed to fear, sudden punishment, or discretionary command. Liberty becomes a lived condition produced by institutions.`
    ],['political-philosophy'],['montesquieu','locke','hobbes'],['The Spirit of the Laws']),
    section('forms-of-government','Republic, monarchy, despotism, and animating principles',[
      `Montesquieu classifies governments by both structure and animating principle. Republics depend on virtue, meaning public-spirited attachment to the common good; monarchies depend on honor, meaning rank, distinction, and regulated ambition; despotisms depend on fear. These categories are not merely labels. They help explain how a political form can decay when its supporting motives disappear or are corrupted.`,
      `Modern readers should not treat this classification as a simple scientific taxonomy. It is a tool for political diagnosis. A republic without civic virtue may become factional or oligarchic. A monarchy without honor may slide toward arbitrary rule. A despotism uses fear because stable law and independent institutions are absent. Montesquieu's deeper point is that laws must fit the passions and social structures that sustain them. Institutions and character form each other.`
    ],['political-philosophy','ethics'],['montesquieu','aristotle','rousseau'],['The Spirit of the Laws']),
    section('separation-of-powers','Separation of powers and moderation',[
      `Montesquieu's most famous doctrine is the separation of legislative, executive, and judicial powers. The point is not administrative tidiness. It is the prevention of arbitrary rule. When the same power makes laws, executes them, and judges cases, citizens have little protection against domination. Liberty requires that power check power, so that ambition, office, and procedure restrain what moral exhortation alone cannot restrain.`,
      `His account drew partly on his interpretation of the English constitution, though historians debate how accurately he understood it. The philosophical importance does not depend on perfect description. Separation of powers became a durable way to think about constitutional liberty because it treats freedom as a structural achievement. A free constitution must anticipate misuse of power. It must make restraint part of the ordinary operation of government rather than a lucky feature of good rulers.`
    ],['political-philosophy'],['montesquieu','locke','rousseau'],['The Spirit of the Laws']),
    section('law-and-social-context','The spirit of laws as relational explanation',[
      `The phrase spirit of the laws points to the relations among laws and the circumstances in which they function. Laws relate to geography, economy, religion, manners, population, property, military organization, and political form. A law that works in one setting may fail in another because it interacts with different habits and institutions. Montesquieu therefore resists abstract legal universalism when it ignores context.`,
      `This contextualism is powerful and dangerous. It is powerful because it prevents naive export of institutions without regard for social conditions. It is dangerous when context becomes excuse for hierarchy, stereotype, or determinism. Montesquieu sometimes overstates the influence of climate in ways later readers should criticize. Still, his basic insight remains important: law is not an isolated command. It is part of a social ecology of motives and powers.`
    ],['political-philosophy'],['montesquieu','adam-smith'],['The Spirit of the Laws']),
    section('commerce-and-manners','Commerce, gentleness, and dependence',[
      `Montesquieu often suggests that commerce can soften manners by making people mutually dependent, interested in peace, and attentive to exchange rather than conquest. Commercial society may weaken certain forms of martial domination and encourage regular law. This idea influenced later Enlightenment discussions, including Scottish Enlightenment reflections on markets, sociability, and modern institutions.`,
      `Yet Montesquieu is not simply a celebrant of commerce. Commerce can also produce inequality, luxury, dependency, colonial exploitation, and corruption. He distinguishes different kinds of commerce and asks how economic life interacts with political liberty. The important lesson is that markets are never merely economic in a narrow sense. They shape character, law, international relations, and the distribution of power.`
    ],['political-philosophy','ethics'],['montesquieu','adam-smith','rousseau'],['The Spirit of the Laws']),
    section('slavery-and-empire','Slavery, empire, and moral limitation',[
      `Montesquieu is famous for his ironic attack on pro-slavery arguments in The Spirit of the Laws. He exposes the absurdity and moral evasions behind attempts to justify enslavement. At the same time, his writing on empire, climate, and non-European peoples includes assumptions that later readers must examine critically. He is an anti-despotic thinker whose own framework remains entangled with some Enlightenment limitations.`,
      `This mixed legacy is important for beginner-friendly honesty. Montesquieu gives later political thought tools for criticizing arbitrary power, slavery, and concentrated rule. He also shows how critique can coexist with partial blindness. Reading him well means using his best insight against his weaknesses: if laws and institutions must be judged by how they structure power, then colonial domination and racial hierarchy require the same scrutiny as domestic tyranny.`
    ],['political-philosophy','ethics'],['montesquieu','rousseau','fanon'],['The Spirit of the Laws']),
    section('influence','Constitutionalism and modern political science',[
      `Montesquieu influenced constitutional design, liberal political thought, sociology, comparative law, and what later became political science. The separation of powers became especially important in debates over constitutional government. His broader method also mattered: study political forms historically and comparatively; ask how institutions shape motives; examine the relation between law and social life; do not reduce politics to ruler commands alone.`,
      `His influence on later thinkers is not one-directional agreement. Rousseau admired and criticized him; Smith shares some interest in manners and commerce while developing a different moral psychology; later liberal constitutionalism often narrows Montesquieu to checks and balances. The wider Montesquieu is richer. He teaches that political liberty depends on a fabric of laws, habits, distributions of power, and forms of judgment that can be damaged gradually.`
    ],['political-philosophy'],['montesquieu','rousseau','adam-smith','locke'],['The Spirit of the Laws','The Social Contract','The Wealth of Nations']),
    section('method-and-limits','Comparative method and its limits',[
      `Montesquieu's method is one reason he remains valuable even where his details fail. He compares legal orders as parts of social wholes, looking for relations among institutions, economies, customs, religion, war, and geography. That method helps students avoid treating a constitution as if it were only text on paper. A court, legislature, or law code works differently depending on habits of obedience, public trust, class power, military organization, and the independence of other institutions.`,
      `The same method needs criticism because comparison can slide into overconfident generalization. Some of Montesquieu's claims about climate and national character show how Enlightenment explanation could become stereotype. The right lesson is not to abandon comparison, but to make it more historically responsible. His best insight is relational: laws must be interpreted in context. His weakness warns that context must be studied with evidence, humility, and attention to the people being described.`,
      `For an atlas view, Montesquieu is especially useful because he sits between older constitutional thinking and later social science. He treats political forms as living arrangements, not merely legal diagrams. That makes him a bridge from Locke and Hobbes to Smith, Rousseau, Tocqueville, and modern institutional analysis. The student should watch how often he asks what kind of people, habits, and fears a law will actually produce.`
    ],['political-philosophy','epistemology'],['montesquieu','adam-smith','rousseau'],['The Spirit of the Laws']),
    section('misunderstandings','Common misunderstandings',[
      `The first misunderstanding is to reduce Montesquieu to the phrase separation of powers. That doctrine is central, but it sits inside a larger theory of law, society, and political moderation. The second misunderstanding is to read him as a simple relativist who thinks every law is justified by local custom. He compares contexts, but he also criticizes despotism, slavery, and arbitrary power.`,
      `A third error is to treat his climate arguments as the core of the work. They are historically important and sometimes deeply flawed, but they do not exhaust his method. A fourth mistake is to think moderation means timidity. For Montesquieu, moderation is the difficult art of preventing power from becoming arbitrary. It requires institutions strong enough to restrain rulers, courts, factions, and sometimes popular passion.`
    ],['political-philosophy'],['montesquieu'],['The Spirit of the Laws']),
    section('reading-strategy','How to read Montesquieu',[
      `Begin with Persian Letters to see his satirical method: making familiar customs look strange. Then read selected books of The Spirit of the Laws on forms of government, liberty, separation of powers, climate, commerce, and slavery. Keep a chart of the relations he studies. His arguments become clearer when you see that each law is being located inside a network of conditions.`,
      `The best guiding question is: what prevents power from becoming arbitrary here? Ask it about constitutions, courts, families, empires, economies, and customs. That question links Montesquieu to modern concerns about executive power, judicial independence, emergency rule, surveillance, and institutional decay. He is not only a historical theorist of eighteenth-century monarchy. He is a philosopher of the fragile conditions under which liberty can be made durable.`,
      `A second question should be: when does explanation become excuse? Montesquieu wants laws to be understood in relation to climate, economy, religion, manners, and history, but contextual explanation can blur into stereotype or apology if it is not disciplined. Read his attack on slavery together with his weaker generalizations about peoples and climates. That pairing shows both the promise and danger of comparative political science. His method teaches that institutions must be studied in context; his limits teach that context must not become a mask for hierarchy.`
    ],['political-philosophy'],['montesquieu','locke','rousseau'],['Persian Letters','The Spirit of the Laws'])
  ],
  'adam-smith':[
    section('overview','Moral sentiment before market mythology',[
      `Adam Smith is often remembered as the father of economics, but he was first a moral philosopher of the Scottish Enlightenment. His two great works, The Theory of Moral Sentiments and The Wealth of Nations, belong together. Smith asks how human beings judge one another, form sympathy, seek approval, cooperate in markets, build institutions, and become vulnerable to vanity and domination. His political economy grows from moral psychology, not from the worship of selfishness.`,
      `Smith matters because he shows how social order can emerge from ordinary human motives without assuming either perfect virtue or total corruption. People care about themselves, but they also want to be seen as worthy by others. Markets can coordinate labor and knowledge, but they can also narrow the mind, intensify inequality, and invite collusion. Smith is therefore more subtle than the slogan of an invisible hand. He studies commercial society as a moral and institutional achievement with real dangers.`
    ],['ethics','political-philosophy','empiricism'],['adam-smith','hume','rousseau','bentham'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('historical-setting','The Scottish Enlightenment and commercial society',[
      `Smith wrote in eighteenth-century Scotland, a context shaped by union with England, expanding commerce, religious debate, colonial empire, agricultural change, and a remarkable intellectual culture around Glasgow and Edinburgh. Scottish Enlightenment thinkers studied human nature historically and socially. They asked how language, law, markets, manners, and institutions developed without being fully planned by any one mind.`,
      `This setting is crucial because Smith is not writing a timeless defense of modern capitalism in its later industrial form. He is analyzing commercial society as it was emerging, with attention to feudal remnants, monopolies, mercantilist restrictions, colonial trade, labor, and moral formation. His question is not whether markets are magic. It is how a society based on exchange can support liberty and prosperity without corrupting judgment or justice.`
    ],['political-philosophy','ethics'],['adam-smith','hume','rousseau'],['The Wealth of Nations']),
    section('life-and-works','Professor, moralist, and political economist',[
      `Smith was born in Kirkcaldy in 1723, studied at Glasgow and Oxford, and later taught moral philosophy at Glasgow. His lectures covered natural theology, ethics, jurisprudence, and political economy. The Theory of Moral Sentiments appeared in 1759 and made his reputation as a moral philosopher. The Wealth of Nations, published in 1776, expanded his analysis of labor, exchange, trade, state policy, and economic development.`,
      `The division between the moral philosopher and the economist is misleading. Smith's political economy presupposes his account of sympathy, judgment, justice, and the desire for esteem. His economics also feeds back into ethics by showing how institutions shape character. A pin factory, a market town, a court of law, and a system of public education are not morally neutral settings. They train attention, dependence, ambition, and responsibility.`
    ],['ethics','political-philosophy'],['adam-smith'],['The Theory of Moral Sentiments','The Wealth of Nations','Lectures on Jurisprudence']),
    section('central-question','How can self-interested beings live in a moral society?',[
      `Smith's central question is how ordinary human beings, who naturally care about their own condition, can nonetheless form moral judgments, cooperate, and sustain social order. He does not begin from isolated calculating individuals. Human beings are spectators of one another. They imagine how others feel, seek approval, resent injury, admire virtue, and internalize standards of judgment. Society forms the self.`,
      `This question connects his ethics and political economy. Exchange often works because people pursue their own projects, but justice and trust are necessary for exchange to remain stable. Moral life cannot depend on benevolence alone, and commercial life cannot survive without legal and ethical constraints. Smith's realism lies in refusing both sentimental optimism and cynical reduction. Human beings are self-regarding, socially responsive, imaginative, vain, generous, and institutionally shaped.`
    ],['ethics','political-philosophy'],['adam-smith','hume','bentham'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('sympathy','Sympathy and moral imagination',[
      `Sympathy, for Smith, is not mere pity. It is the imaginative capacity to enter into another person's situation and judge whether their feelings are appropriate to it. We do not literally feel exactly what others feel, but we imaginatively adjust ourselves toward their perspective. Moral judgment arises from this social process of comparing sentiments, circumstances, and responses.`,
      `This account makes ethics relational without making it arbitrary. We learn to moderate our own passions because we want others to be able to sympathize with us. We also judge others by imagining what we would feel in their place. Sympathy can fail through distance, prejudice, class interest, or vanity, but it remains the basic mechanism by which moral life becomes shared. Smith's moral philosophy is therefore a theory of social perception.`
    ],['ethics'],['adam-smith','hume'],['The Theory of Moral Sentiments']),
    section('impartial-spectator','The impartial spectator and self-command',[
      `The impartial spectator is Smith's name for the internalized standpoint from which we judge our own conduct as if from the perspective of a fair and well-informed observer. It is not an actual person hidden inside us. It is a moral achievement formed through social life. By imagining how an impartial spectator would view our actions, we can correct vanity, resentment, cowardice, and self-deception.`,
      `This idea gives Smith an account of conscience without relying only on rules or consequences. Moral maturity involves learning to see oneself with proportion. The impartial spectator does not eliminate feeling; it disciplines feeling. Self-command becomes a virtue because social life requires us to moderate passions so others can live with us. Smith's ethics therefore emphasizes character, judgment, and emotional education as much as isolated choice.`
    ],['ethics','virtue-ethics'],['adam-smith','aristotle','hume'],['The Theory of Moral Sentiments']),
    section('justice','Justice as the foundation of social order',[
      `Smith distinguishes beneficence from justice. Beneficence is admirable but cannot usually be forced; justice is necessary and may be enforced because injury destroys the conditions of society. A community can survive with limited generosity, but it cannot survive if people may freely steal, defraud, assault, or violate basic rights. Justice is the grammar of peaceful coexistence.`,
      `This distinction matters for political economy. Markets require stable expectations, property rules, courts, trust, and protection against coercion. Smith is not an anarchic market thinker. He repeatedly criticizes monopolies, collusion, corruption, empire, and policies that serve merchants at public expense. The state must secure justice, provide certain public works, support education, and resist capture by powerful interests. Commercial freedom depends on political and legal structure.`
    ],['ethics','political-philosophy'],['adam-smith','locke','bentham'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('division-of-labor','Division of labor and its moral cost',[
      `The Wealth of Nations famously begins with the division of labor, using pin production to show how specialization increases productivity. Smith sees that complex cooperation can arise when workers specialize and exchange. No single mind needs to plan every detail of production for social coordination to occur. This insight became foundational for political economy.`,
      `Yet Smith also warns that repetitive specialized labor can make workers intellectually and morally narrow if society does nothing to counteract it. This warning is often forgotten. Commercial society generates wealth, but it can damage the capacities of those whose work becomes monotonous. Smith therefore supports public education and institutional remedies. The same process that creates prosperity can also produce human diminishment unless political judgment intervenes.`
    ],['political-philosophy','ethics'],['adam-smith','marx'],['The Wealth of Nations']),
    section('invisible-hand','The invisible hand and unintended order',[
      `The invisible hand is one of the most overused phrases in the history of social thought. Smith uses the image sparingly, and it should not be read as a universal guarantee that self-interest always produces public good. His deeper point is that social order often includes unintended consequences. People pursuing local aims can sometimes contribute to broader patterns they did not design.`,
      `This idea is important, but Smith never treats it as a substitute for moral and legal judgment. Merchants may conspire against the public, colonial policy may serve narrow interests, and admiration for wealth may corrupt moral judgment. Unintended order can be beneficial, but unintended harm is also real. A careful Smithian asks when decentralized action works, when it fails, and what institutions make the difference.`
    ],['political-philosophy','ethics'],['adam-smith','hume'],['The Wealth of Nations','The Theory of Moral Sentiments']),
    section('commercial-society','Commercial society, inequality, and moral corruption',[
      `Smith admires many achievements of commercial society: increased productivity, interdependence, refinement of manners, and escape from some feudal dependencies. But he is sharply aware of moral corruption. People tend to admire the rich and powerful more than the wise and virtuous. The desire for status can lead to anxiety, servility, and injustice. Commercial society can improve living standards while training people to mistake wealth for worth.`,
      `This is one reason Smith should be read with Rousseau, not only against him. Rousseau offers a more radical critique of inequality and dependence, while Smith gives a more institutionally balanced account of markets and moral judgment. Both worry about comparison, vanity, and the social production of desire. Smith's distinctive contribution is to ask how commercial society can be disciplined by justice, education, and moral spectatorship rather than simply rejected or idolized.`
    ],['ethics','political-philosophy'],['adam-smith','rousseau','marx'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('influence-and-controversy','Influence, appropriation, and the Adam Smith problem',[
      `Smith influenced economics, liberal political thought, moral philosophy, sociology, and debates over markets and state power. Later readers often separated The Wealth of Nations from The Theory of Moral Sentiments, creating the so-called Adam Smith problem: how can the same thinker emphasize sympathy in one work and self-interest in another? Many scholars now regard the problem as largely produced by bad separation. Smith analyzes different domains of social life with a shared moral psychology.`,
      `The controversy remains useful because it reveals how easily Smith is appropriated. Some use him as a symbol of unregulated markets; others emphasize his moral criticism of merchants and inequality. The better approach is to read the whole Smith. He is a philosopher of sympathy, justice, commercial coordination, institutional design, and moral danger. That whole picture is more demanding than any slogan.`
    ],['ethics','political-philosophy'],['adam-smith','hume','bentham','mill'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('branch-connections','Smith between ethics, politics, and social explanation',[
      `Smith is hard to place because later disciplines divided what his philosophy holds together. In ethics, he studies sympathy, conscience, virtue, self-command, and moral judgment. In political philosophy, he studies justice, liberty, public goods, law, taxation, and state capture. In social theory, he studies unintended order, division of labor, status, and the formation of manners. The unity is his question of how social beings become coordinated and judged.`,
      `This makes Smith an excellent counterweight to simplified market individualism. He does not begin with a lone consumer choosing in empty space. He begins with persons who need recognition, compare themselves with others, live under law, and inherit institutions. Markets are one form of social coordination within that wider moral world. Reading Smith this way also clarifies why Marx, Mill, and later political economists could learn from him while criticizing commercial society more sharply.`,
      `Smith also helps connect moral sentiment to institutional design. If people naturally admire wealth, then law and education must resist servility before rank and fortune. If merchants have concentrated interests, then policy must watch for capture. If workers can be narrowed by specialization, then public education is not optional decoration. Smith's social world is morally fragile, and that fragility is exactly why political economy remains a branch of moral philosophy.`
    ],['ethics','political-philosophy','empiricism'],['adam-smith','hume','marx','mill'],['The Theory of Moral Sentiments','The Wealth of Nations']),
    section('reading-strategy','How to read Smith',[
      `Begin with The Theory of Moral Sentiments, especially sympathy, the impartial spectator, self-command, justice, and the corruption caused by admiration for the wealthy. Then read selected books of The Wealth of Nations on the division of labor, natural liberty, mercantilism, public works, education, and the interests of merchants. Keep asking how moral psychology and institutional analysis illuminate each other.`,
      `The best beginner question is: what kind of society forms good judgment? That question prevents Smith from becoming only an economist of exchange. It reveals him as a moral philosopher of attention, approval, law, labor, and dependency. Read him beside Hume for sentiment, Rousseau for inequality, and later political economy for market institutions. Smith rewards readers who resist both worship and dismissal.`,
      `It also helps to track Smith's warnings as carefully as his defenses of commercial life. Make a list of what he criticizes: monopoly, merchant capture, colonial policy, admiration of wealth, intellectual narrowing through repetitive labor, and injustice disguised as public interest. Those warnings prevent the invisible hand from becoming a slogan. Smith's real question is institutional: under what legal, moral, and educational conditions can self-interest contribute to social cooperation rather than corruption?`
    ],['ethics','political-philosophy','empiricism'],['adam-smith','hume','rousseau','bentham'],['The Theory of Moral Sentiments','The Wealth of Nations','Lectures on Jurisprudence'])
  ],
  'wollstonecraft':[
    section('overview','Equality, education, and the unfinished Enlightenment',[
      `Mary Wollstonecraft is a foundational figure in feminist political philosophy because she argues that women's apparent inferiority is produced by social arrangements rather than nature. Her A Vindication of the Rights of Woman turns Enlightenment ideals of reason, virtue, education, and rights against a culture that denied women the conditions for developing them. She does not ask for women to be admired as delicate ornaments. She asks for them to be treated as rational and moral agents.`,
      `Wollstonecraft matters because she exposes a contradiction at the center of modern liberty. A society can praise reason and rights while training half the population for dependency, beauty, obedience, and emotional manipulation. Her critique is not only about women. It is about the kind of persons political orders produce. If citizens are made unfree by education, law, and custom, then formal language about liberty becomes thin.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft','mary-astell','rousseau','mill'],['A Vindication of the Rights of Woman']),
    section('historical-setting','Revolution, rights, and gendered citizenship',[
      `Wollstonecraft wrote during the age of the American and French Revolutions, when rights, representation, sovereignty, and citizenship were being radically rethought. The same period that proclaimed universal language often excluded women from political standing and treated domestic dependence as natural. Debates over education, virtue, marriage, property, and sensibility shaped what women were expected to become.`,
      `Her work responds directly to this contradiction. A Vindication of the Rights of Men defends reform and criticizes hereditary privilege. A Vindication of the Rights of Woman extends the question of rights and virtue into gender relations. The French Revolution also shaped her hopes and disappointments. She was not writing an abstract equality puzzle. She was writing in a moment when the meaning of modern political membership was being fought over.`
    ],['feminist-philosophy','political-philosophy'],['wollstonecraft','rousseau','montesquieu'],['A Vindication of the Rights of Men','A Vindication of the Rights of Woman','An Historical and Moral View of the French Revolution']),
    section('life-and-works','A writer across genres and crises',[
      `Wollstonecraft was born in 1759 and supported herself through work as a companion, governess, teacher, translator, reviewer, and author. Her life included economic insecurity, family difficulty, radical friendships, travel, love, motherhood, and political disappointment. These facts matter because her philosophy repeatedly asks how women can become independent when law and custom make dependence ordinary.`,
      `Her writings include educational works, political vindications, travel writing, historical reflection, and fiction. Maria, or The Wrongs of Woman, left unfinished at her death, explores marriage, sexuality, property, confinement, and female solidarity in narrative form. Reading only Rights of Woman misses the range of her critique. She used whatever genres were available to examine how institutions enter intimate life.`
    ],['feminist-philosophy','political-philosophy'],['wollstonecraft'],['A Vindication of the Rights of Woman','Maria, or The Wrongs of Woman','Letters Written During a Short Residence in Sweden, Norway, and Denmark']),
    section('central-question','What would women become under equal education?',[
      `Wollstonecraft's central question is what women could become if educated as rational beings rather than trained for dependence. She does not deny that many women of her society appear frivolous, vain, or intellectually narrow. Her argument is that such traits are produced by social expectations. If women are taught that beauty and male approval are their main sources of security, their apparent weakness reflects their education.`,
      `This question is philosophical because it asks how character is formed. Moral and political theories often assume adult agents already capable of choice. Wollstonecraft asks how agency is built or damaged before choice appears. She therefore links education, equality, virtue, and freedom. A society that deforms women's reason and then blames them for lacking independence commits both injustice and bad philosophy.`
    ],['feminist-philosophy','ethics','political-philosophy'],['wollstonecraft','mary-astell','rousseau'],['A Vindication of the Rights of Woman']),
    section('reason-and-virtue','Reason, virtue, and moral equality',[
      `Wollstonecraft grounds her argument in the claim that virtue must be the same in kind for women and men. If virtue depends on reason, self-command, truthfulness, courage, and concern for justice, then women cannot have a separate ornamental morality based on pleasing others. To make women charming rather than strong is to corrupt them morally and politically.`,
      `Her appeal to reason can sound austere, especially to readers suspicious of Enlightenment universalism. But Wollstonecraft is not asking women to become disembodied intellects. She is rejecting a gender order that makes emotion and dependence substitutes for moral agency. Reason names the capacity to judge, deliberate, resist flattery, and act from principle. Without that capacity, neither love nor citizenship can be fully free.`
    ],['ethics','feminist-philosophy'],['wollstonecraft','kant','mary-astell'],['A Vindication of the Rights of Woman']),
    section('education-and-dependence','Education as the manufacture of dependency',[
      `Wollstonecraft's critique of education targets novels, conduct books, manners, and social expectations that teach girls to seek admiration rather than understanding. Women are encouraged to become pleasing, delicate, emotional, and dependent. Then their dependence is represented as natural femininity. This is the same circular structure Astell had identified earlier: a society trains women for weakness and then cites weakness as proof of inferiority.`,
      `Her solution is not merely more information for women. She wants education that develops judgment, physical strength, useful knowledge, moral seriousness, and economic independence where possible. She also criticizes men formed by luxury and domination. Bad education damages both sexes because it replaces friendship with power and performance. Equality requires a different formation of desire, not just a legal adjustment.`
    ],['feminist-philosophy','ethics','political-philosophy'],['wollstonecraft','mary-astell','rousseau'],['A Vindication of the Rights of Woman']),
    section('rousseau','Argument with Rousseau and separate-spheres education',[
      `Wollstonecraft's dispute with Rousseau is central. Rousseau's Emile offers a powerful theory of education for male citizenship and authenticity, but his account of Sophie trains women primarily to please and support men. Wollstonecraft sees this as a betrayal of Rousseau's own concern with freedom. A boy is educated to become independent; a girl is educated to become useful to his independence.`,
      `Her criticism is not that Rousseau is unimportant. It is that his gendered education reveals a limit in his political imagination. If women are formed for dependence, men cannot become genuinely virtuous companions either. Marriage becomes performance and manipulation rather than friendship. Wollstonecraft uses Rousseau against himself: any education worthy of free persons must cultivate reason and virtue in women as well as men.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft','rousseau'],['A Vindication of the Rights of Woman','Emile']),
    section('marriage-family-citizenship','Marriage, family, and citizenship',[
      `Wollstonecraft criticizes marriage when it turns women into legal and economic dependents rewarded for beauty and obedience. She does not reject family life as such. She wants marriage to become friendship between equals, grounded in respect and shared virtue rather than domination or romantic illusion. Without equality, intimate life teaches both parties bad moral habits.`,
      `This domestic argument is also political. Children learn citizenship in households. If homes are organized around tyranny, flattery, and dependency, public virtue is weakened. Wollstonecraft therefore refuses to separate private and public life sharply. A society cannot cultivate free citizens while accepting unfreedom as the ordinary training ground of women. The home is one of the first political institutions.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft','mary-astell','mill'],['A Vindication of the Rights of Woman','Maria, or The Wrongs of Woman']),
    section('sensibility-and-emotion','Critique of sensibility without contempt for feeling',[
      `Wollstonecraft attacks the culture of sensibility that prized intense feeling, delicacy, and emotional display, especially in women. Her concern is not that feeling is worthless. It is that socially rewarded sentiment can become self-indulgent, theatrical, and morally unreliable when cut off from judgment. A person trained to feel beautifully may still fail to act justly.`,
      `This part of her work is sometimes misunderstood as hostility to emotion. It is better read as a demand for educated feeling. Emotions should be connected with truth, responsibility, and durable concern for others. Sentiment without reason can reinforce dependency because it teaches women to secure power indirectly through charm, tears, and manipulation. Wollstonecraft wants women to have direct moral standing instead.`
    ],['ethics','feminist-philosophy'],['wollstonecraft','hume','adam-smith'],['A Vindication of the Rights of Woman']),
    section('influence','Legacy in liberal, republican, and feminist thought',[
      `Wollstonecraft influenced later feminism, liberal political thought, debates over women's education, and critiques of marriage and domestic dependence. Her legacy is not simple. Later feminists have admired her insistence on reason and equality while also questioning her suspicion of some forms of femininity, her class assumptions, and the limits of her account of sexuality, labor, and race.`,
      `Her influence is strongest when read as an unfinished argument rather than a finished doctrine. She opens a line of thought that runs through Mill's defense of women's equality, Beauvoir's analysis of woman as Other, and contemporary feminist accounts of social construction and agency. The recurring question is how power forms people before it appears as their choice. Wollstonecraft made that question unavoidable.`
    ],['feminist-philosophy','political-philosophy'],['wollstonecraft','mill','beauvoir','judith-butler'],['A Vindication of the Rights of Woman','The Subjection of Women','The Second Sex']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is that Wollstonecraft simply wanted women to become like men. Her deeper claim is that virtue should not be divided into masculine reason and feminine charm. Another misunderstanding is that she rejected love, beauty, or motherhood. She criticizes social forms that make those goods substitutes for freedom, not every intimate attachment.`,
      `A third mistake is to treat her as a fully modern egalitarian by current standards. Her work bears marks of class, empire, religion, and eighteenth-century assumptions. That does not erase its force. It helps readers see how feminist thought develops through internal criticism. Wollstonecraft gives powerful tools for equality while also inviting later thinkers to ask whom her account still leaves at the margins.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft'],['A Vindication of the Rights of Woman']),
    section('agency-and-limits','Agency, class, empire, and unfinished equality',[
      `Wollstonecraft's strongest arguments also reveal limits that later feminist philosophy must address. She criticizes class privilege and hereditary rank, but she often writes from assumptions about respectability, labor, and civilization that do not fully include poor women, colonized women, or women outside European political debates. This does not make her useless. It shows how an argument for universal reason can still carry partial social imagination.`,
      `That tension is instructive. Wollstonecraft gives later thinkers a method for criticizing her own exclusions: ask whether the conditions for rational agency are actually being secured for everyone, not only for women closest to the writer's social world. This makes her work a living starting point rather than a monument. Her demand for education, independence, and equal virtue invites expansion into questions of labor, race, empire, sexuality, disability, and household economics.`,
      `Her work also shows why agency cannot be reduced to inner willpower. A woman may be courageous and intelligent, yet still be blocked by property law, sexual reputation, lack of schooling, economic dependency, and the threat of social punishment. Wollstonecraft's moral language sometimes sounds individual, but her argument keeps pointing to institutions. To become free, people need social arrangements that do not make dependence the price of survival. That insight remains central to feminist social philosophy. It also explains why her educational argument is never merely curricular; it is a theory of social power.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft','angela-davis','bell-hooks'],['A Vindication of the Rights of Woman','Maria, or The Wrongs of Woman']),
    section('reading-strategy','How to read Wollstonecraft',[
      `Start with A Vindication of the Rights of Woman, focusing on education, virtue, Rousseau, marriage, and sensibility. Then read A Vindication of the Rights of Men to see her response to hereditary privilege and revolutionary politics. After that, read Maria, or The Wrongs of Woman, because the fiction makes visible the institutional and emotional costs of marriage, property, and confinement.`,
      `The best guiding question is: how does society manufacture the traits it calls natural? That question connects Wollstonecraft to Astell, Rousseau, Mill, Beauvoir, Butler, and contemporary feminist theory. It also keeps the text alive for modern readers. Wollstonecraft is not merely asking for inclusion in education. She is asking what kind of human beings education, law, and intimacy are designed to produce.`,
      `A second pass should focus on tone and tension. Wollstonecraft can sound severe toward femininity, sentiment, and dependence, and later readers should ask what her criticism reveals and what it obscures. Is she attacking women, or the social training that rewards women for weakness? Does her ideal of rational virtue leave enough room for bodily vulnerability, pleasure, care, and difference? These questions make the text richer. Wollstonecraft's power lies in exposing manufactured dependency; her limits invite later feminist work to build accounts of equality that do not require suspicion toward every gendered form of feeling. That later expansion is part of her legacy.`
    ],['feminist-philosophy','political-philosophy','ethics'],['wollstonecraft','mary-astell','rousseau','mill'],['A Vindication of the Rights of Woman','A Vindication of the Rights of Men','Maria, or The Wrongs of Woman'])
  ],
  'martha-nussbaum':[
    section('overview','Capabilities, dignity, emotion, and the humanities',[
      `Martha Nussbaum is a contemporary moral and political philosopher best known for the capabilities approach, her work on emotions, and her defense of literature and the humanities as resources for ethical judgment. Her philosophy joins ancient Greek ethics, liberal political theory, feminism, law, development, disability, animal ethics, and education. The connecting question is what people need in order to live lives worthy of human dignity.`,
      `Nussbaum matters because she resists thin measures of social success. A society cannot be judged only by income, preference satisfaction, or formal rights. It must be judged by what people are actually able to be and do. Can they think, imagine, affiliate, play, participate, move safely, form attachments, and exercise practical reason? This focus makes justice concrete without reducing it to one simple metric.`
    ],['ethics','political-philosophy','feminist-philosophy'],['martha-nussbaum','aristotle','rawls','anscombe'],['Women and Human Development','Creating Capabilities']),
    section('historical-setting','After Rawls, development economics, and feminist critique',[
      `Nussbaum's work emerges in a late twentieth-century setting shaped by debates over liberal justice, global development, feminism, multiculturalism, disability, human rights, and the role of emotions in public life. Rawls had transformed political philosophy by asking what principles free and equal citizens would choose under fair conditions. Development debates were also asking why economic growth alone failed to capture human well-being.`,
      `The capabilities approach, developed in conversation with Amartya Sen while taking its own philosophical form in Nussbaum's work, responds to that setting. It asks what real opportunities people have, not merely what resources they possess. Feminist concerns are central because women may formally have rights while lacking education, bodily safety, political voice, or control over their environment. Justice must examine lived possibility.`
    ],['political-philosophy','ethics','feminist-philosophy'],['martha-nussbaum','rawls','wollstonecraft'],['Women and Human Development','Creating Capabilities','A Theory of Justice']),
    section('life-and-works','A philosopher across classics, law, and public ethics',[
      `Nussbaum's career is unusual in its range. She began with deep work in ancient Greek philosophy and tragedy, including The Fragility of Goodness, and developed influential arguments about emotion, literature, ethics, and political justice. Later books address capabilities, global justice, religion and democracy, disgust and law, animal justice, education, and aging. This breadth is not a lack of focus. It reflects a view of philosophy as answerable to the complexity of life.`,
      `Her major works for beginners include The Fragility of Goodness, Love's Knowledge, Women and Human Development, Frontiers of Justice, Creating Capabilities, Political Emotions, and Upheavals of Thought. Different readers will enter through different doors: Aristotle, feminism, literature, development, law, or emotions. The recurring concern is how vulnerable beings can be supported by institutions that respect dignity rather than merely manage behavior.`
    ],['ethics','political-philosophy','feminist-philosophy'],['martha-nussbaum','aristotle','rawls'],['The Fragility of Goodness',"Love's Knowledge",'Women and Human Development','Creating Capabilities']),
    section('central-question','What must a life be able to include?',[
      `Nussbaum's central question is not simply how much welfare a person has, but what a person is actually able to do and be. A person may have income but lack safety, education, bodily integrity, political voice, or social respect. A person may formally have liberty while social conditions make meaningful choice nearly impossible. Justice must therefore examine capabilities, the real opportunities for central forms of human functioning.`,
      `This question shifts political philosophy from abstract distribution to human lives. It asks whether institutions secure thresholds below which a dignified life is not possible. Nussbaum does not require everyone to live the same life. Capabilities protect space for choice. The state should secure opportunities for functioning, while individuals may choose whether and how to exercise them. This preserves pluralism while refusing indifference to deprivation.`
    ],['political-philosophy','ethics'],['martha-nussbaum','rawls'],['Creating Capabilities','Women and Human Development']),
    section('central-capabilities','The central capabilities list',[
      `Nussbaum proposes a list of central capabilities, including life, bodily health, bodily integrity, senses and imagination, emotions, practical reason, affiliation, relation to other species, play, and control over one's environment. The list is meant to identify areas where political institutions must secure a threshold of real opportunity. It is not a ranking of pleasures or a script for a perfect life.`,
      `The list is controversial because it looks more substantive than some liberal theories allow. Critics ask who gets to define central capabilities and whether the list is too universal. Nussbaum answers that any defensible political conception of justice needs some substantive account of human dignity. The list should be open to argument, cross-cultural criticism, and democratic reflection, but not empty. Without content, appeals to dignity can become decorative.`
    ],['political-philosophy','ethics','feminist-philosophy'],['martha-nussbaum','rawls'],['Women and Human Development','Creating Capabilities']),
    section('aristotle-and-vulnerability','Aristotle, flourishing, and vulnerability',[
      `Nussbaum's capabilities approach draws from Aristotle without simply reviving ancient perfectionism. Aristotle asked what human flourishing requires and treated human beings as social, rational, embodied, and vulnerable. Nussbaum adapts that concern for flourishing to modern pluralist politics. She wants an account thick enough to notice hunger, violence, humiliation, disability, and exclusion, but political enough to respect different comprehensive doctrines.`,
      `Her early work on Greek tragedy and Aristotle emphasizes the fragility of goodness. Human lives depend on circumstances outside complete control: health, love, political order, luck, and loss. This sensitivity to vulnerability shapes her later justice theory. A dignified society is not one that imagines citizens as invulnerable choosers. It is one that builds support for embodied, dependent, emotionally complex beings.`
    ],['ethics','virtue-ethics','political-philosophy'],['martha-nussbaum','aristotle'],['The Fragility of Goodness','Creating Capabilities']),
    section('emotions','Emotions as intelligent appraisals',[
      `Nussbaum argues that emotions are not blind surges opposed to reason. They often contain judgments or appraisals about what matters to us. Grief, fear, anger, compassion, love, and shame reveal how we understand value and vulnerability. This account lets ethics and politics take emotion seriously without surrendering to manipulation. Emotions can be educated, criticized, and interpreted.`,
      `Her work on emotions matters for public philosophy. Law and politics often rely on feelings such as disgust, fear, patriotism, compassion, and anger. Some emotions support justice; others can stigmatize and exclude. Nussbaum's analysis asks which emotions are appropriate to a democratic culture of equal dignity. She is especially wary of disgust when it marks groups as contaminating or subhuman.`
    ],['ethics','political-philosophy','philosophy-of-mind'],['martha-nussbaum','adam-smith','hume'],['Upheavals of Thought','Hiding from Humanity','Political Emotions']),
    section('feminism-and-global-justice','Women, development, and global justice',[
      `Women and Human Development applies the capabilities approach to women's lives in contexts where formal rights may coexist with violence, illiteracy, malnutrition, unequal family power, and economic dependence. Nussbaum argues that justice must look at each person as an end, not at households as if their benefits were automatically shared. A family's average welfare can hide severe deprivation of women and girls.`,
      `This feminist dimension is central, not an application added later. Capabilities reveal how oppression works through custom, law, bodily vulnerability, unpaid labor, and limited education. They also avoid treating women only as victims. The goal is to secure conditions under which each person can exercise practical reason, affiliation, work, political participation, and bodily integrity. Equality becomes a question of real possibility.`
    ],['feminist-philosophy','political-philosophy','ethics'],['martha-nussbaum','wollstonecraft','beauvoir'],['Women and Human Development','Creating Capabilities']),
    section('literature-and-judgment','Literature and the education of moral perception',[
      `Nussbaum has long argued that literature can educate moral attention. Novels and tragedies present particular lives, conflicting goods, vulnerability, and the texture of perception in ways that abstract theory may miss. This does not mean literature replaces argument. It means ethical judgment needs imagination and responsiveness to particulars, especially when rules are too blunt to capture what matters.`,
      `This commitment connects Nussbaum to a wider humanistic philosophy. She defends education that cultivates critical thinking, empathy, historical understanding, and the capacity to see others as fully human. In political terms, democratic citizenship requires more than technical skill. It requires the ability to imagine lives different from one's own and to resist fear-driven simplifications. Literature can be one training ground for that capacity.`
    ],['ethics','aesthetics','political-philosophy'],['martha-nussbaum','iris-murdoch'],["Love's Knowledge",'Cultivating Humanity','Not for Profit']),
    section('controversies','Universalism, liberalism, and disagreement',[
      `Nussbaum's work generates serious controversies. Some critics worry that the capabilities list imposes a universal account of human good across cultures. Others argue that her liberalism remains too individualistic or too dependent on state protection. Some disability theorists and animal ethicists welcome her expansion of justice while questioning details. Critics of political emotions worry about how civic feeling can be cultivated without pressure toward conformity.`,
      `These debates are philosophically valuable because Nussbaum's theory is intentionally substantive. It makes claims that can be challenged. A completely empty account of justice would avoid controversy by saying little. Nussbaum's view invites argument about what dignity requires, how democratic legitimacy works, whether a threshold is enough, and how to respect pluralism without tolerating severe deprivation.`
    ],['political-philosophy','ethics','feminist-philosophy'],['martha-nussbaum','rawls','nozick'],['Creating Capabilities','Frontiers of Justice','Political Emotions']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is that capabilities require everyone to function in the same way. Nussbaum distinguishes capabilities from actual functionings: justice should secure real opportunities, while people may choose differently. Another misunderstanding is that her list is merely a development checklist. It is a philosophical account of dignity, practical reason, embodiment, affiliation, and political responsibility.`,
      `A third mistake is to treat her as only an applied ethicist. Her work rests on deep engagements with Aristotle, tragedy, moral psychology, liberalism, feminism, and law. A fourth misunderstanding is that attention to emotion means replacing reason with feeling. Nussbaum's point is almost the reverse: emotions are intelligent enough to be assessed, educated, and held responsible within ethical and political life.`
    ],['ethics','political-philosophy'],['martha-nussbaum'],['Creating Capabilities','Upheavals of Thought']),
    section('branch-connections','Why Nussbaum crosses so many boundaries',[
      `Nussbaum is not easy to file because her work deliberately crosses branch boundaries. The capabilities approach is political philosophy, but it depends on ethical claims about dignity, practical reason, affiliation, and vulnerability. Her account of emotions belongs to moral psychology, but it also matters for law and democracy. Her work on literature belongs to aesthetics and ethics, but it is also a theory of how citizens learn to perceive particular lives.`,
      `This range is part of the argument. A theory of justice that ignores emotion may misunderstand fear, compassion, disgust, and stigma. A theory of emotion that ignores institutions may become private therapy. A theory of education that ignores democracy may train skill without judgment. Nussbaum's philosophy asks these areas to answer to one another. That is why she can move from Aristotle to constitutional law, from tragedy to development, and from feminism to animal ethics without treating them as unrelated projects.`,
      `The capabilities approach also gives the atlas a concrete way to connect ancient virtue ethics with contemporary justice. Aristotle helps Nussbaum ask what flourishing requires, but liberal politics requires space for plural choices. Feminism helps her see how deprivation hides inside households and customs. Law helps her ask what institutions can actually secure. The resulting view is not merely a theory of resources; it is a theory of what a person must be genuinely able to pursue in practice.`
    ],['ethics','political-philosophy','aesthetics'],['martha-nussbaum','aristotle','rawls','iris-murdoch'],['Creating Capabilities','Upheavals of Thought','Love\'s Knowledge']),
    section('reading-strategy','How to read Nussbaum',[
      `A good route depends on the reader's interest. For justice and development, begin with Creating Capabilities, then Women and Human Development. For ancient ethics, begin with The Fragility of Goodness. For emotion, read Upheavals of Thought or a shorter selection on disgust, compassion, or political emotions. For literature and moral perception, read Love's Knowledge.`,
      `The guiding question should be: what real opportunities must a society secure for each person? Keep that question concrete. Ask it about gender, disability, poverty, education, animals, religion, and democratic emotion. Nussbaum's work is ambitious because it refuses to choose between philosophical argument and human detail. It wants justice theory to remain answerable to the texture of actual lives.`,
      `It is also useful to compare her with Rawls and Sen. Rawls clarifies the liberal concern for fairness among citizens; Sen emphasizes comparative freedom and resists a fixed canonical list; Nussbaum gives a more definite account of central capabilities and dignity. The comparison reveals her main risk and strength at once. A substantive list can look paternalistic, but without substance justice can ignore deprivation that hides behind choice, culture, or household averages. Read her by testing the list against concrete lives rather than treating it as a slogan. The cases matter. Concrete examples decide the issue.`
    ],['ethics','political-philosophy','feminist-philosophy'],['martha-nussbaum','aristotle','rawls'],['Creating Capabilities','Women and Human Development','The Fragility of Goodness',"Love's Knowledge"])
  ],
  'judith-butler':[
    section('overview','Gender, norms, performativity, and livable life',[
      `Judith Butler is one of the most influential contemporary philosophers of gender, embodiment, language, power, and social norms. Gender Trouble made Butler famous for the theory of gender performativity, but their work extends far beyond that phrase. Butler asks how subjects are formed by norms, how bodies become intelligible, how language can injure, how vulnerability is politically distributed, and what makes a life socially recognizable as livable.`,
      `Butler matters because they challenge the idea that identity is a simple inner essence expressed outwardly. Social norms do not merely describe gender, sexuality, kinship, and personhood; they help produce the field in which people can appear as coherent subjects. This does not mean individuals can invent themselves without constraint. It means agency happens within norms that both enable and restrict recognition. Butler's philosophy is difficult because it studies power inside the conditions of intelligibility itself.`
    ],['feminist-philosophy','continental-philosophy','philosophy-of-language'],['judith-butler','beauvoir','foucault','derrida'],['Gender Trouble','Bodies That Matter']),
    section('historical-setting','Feminist theory after structuralism and queer politics',[
      `Butler's early work emerged from feminist theory, poststructuralism, psychoanalysis, queer politics, and debates over the category of women. Feminist movements needed shared political language, but the category women was never simple. It could exclude differences of race, class, sexuality, nation, disability, and gender variance. Queer theory also challenged stable assumptions about sex, gender, and desire.`,
      `This setting explains why Butler asks not only how women are oppressed, but how gendered categories are produced and regulated. Foucault's analysis of power, Derrida's work on language, Beauvoir's claim that one becomes a woman, and psychoanalytic accounts of subject formation all form part of the background. Butler does not merely add a new identity category. They question how identity categories become politically necessary and politically dangerous at the same time.`
    ],['feminist-philosophy','continental-philosophy'],['judith-butler','beauvoir','foucault','derrida'],['Gender Trouble','The Second Sex','Discipline and Punish']),
    section('life-and-works','A body of work beyond one famous book',[
      `Butler was born in 1956 and became widely known through Gender Trouble in 1990. Bodies That Matter refined and corrected misunderstandings of performativity. Excitable Speech examined language, injury, and censorship. Undoing Gender explored recognition, kinship, and livability. Later works such as Precarious Life, Frames of War, and Notes Toward a Performative Theory of Assembly connect vulnerability, violence, grief, and collective politics.`,
      `This range matters because Butler is often reduced to a slogan about gender being performed. The broader project is about normativity and social life: who can appear, speak, mourn, assemble, desire, and be recognized without violence. Butler's prose can be demanding, partly because they work across German idealism, phenomenology, psychoanalysis, speech act theory, deconstruction, and political theory. The difficulty serves an attempt to think power before it becomes obvious.`
    ],['feminist-philosophy','continental-philosophy','political-philosophy'],['judith-butler','foucault','derrida'],['Gender Trouble','Bodies That Matter','Excitable Speech','Undoing Gender','Precarious Life']),
    section('central-question','How do norms make some lives intelligible?',[
      `Butler's central question is how social norms make some bodies, genders, desires, and lives intelligible while rendering others incoherent, impossible, or disposable. Recognition is not merely a polite social benefit. To be recognized as a person, a gendered subject, a grievable life, or a legitimate speaker affects one's ability to survive and act. Norms are therefore productive and violent at once.`,
      `This question changes the task of feminist philosophy. It is not enough to ask for equality between already settled groups if the categories themselves are shaped by power. Butler asks how categories are made, repeated, challenged, and opened. Agency is not outside norms, because subjects are formed through them. But agency can occur through repetition with variation, failed citation, collective resistance, and exposure of norms as contingent rather than natural.`
    ],['feminist-philosophy','continental-philosophy','political-philosophy'],['judith-butler','beauvoir','foucault'],['Gender Trouble','Undoing Gender']),
    section('performativity','Gender performativity without voluntarism',[
      `Gender performativity is often misunderstood as the claim that gender is a costume one freely chooses each morning. Butler's actual claim is more subtle. Gender is constituted through repeated acts, gestures, norms, expectations, and social recognitions that create the appearance of a stable inner identity. The performance is not usually deliberate theater. It is the compelled repetition through which gender becomes socially real.`,
      `This view draws from speech act theory and from feminist and poststructuralist accounts of subject formation. A performative utterance does something under the right conditions; gendered acts similarly help produce what they seem to express. But the repetition is never perfect. Because norms must be repeated, they can also be cited differently, parodied, disrupted, or exposed. Performativity therefore explains both constraint and possible transformation.`
    ],['feminist-philosophy','philosophy-of-language','continental-philosophy'],['judith-butler','derrida','beauvoir'],['Gender Trouble','Bodies That Matter']),
    section('sex-and-materiality','Bodies, sex, and materialization',[
      `After Gender Trouble, Butler was criticized as if they denied the reality of bodies. Bodies That Matter responds by arguing that materiality is not outside discourse in a simple way. Bodies are real, vulnerable, and forceful, but what counts as a sexed body is organized through norms, medical classifications, legal categories, and repeated practices of recognition. Discourse does not invent flesh from nothing; it shapes the terms under which bodies matter socially.`,
      `The idea of materialization helps avoid two extremes. One extreme treats sex as a brute natural fact untouched by interpretation. The other imagines bodies as pure linguistic constructions. Butler's position is harder: bodies are material, but materiality becomes politically meaningful through regulatory norms. This is why debates over intersex bodies, trans lives, medicine, kinship, and law are not merely semantic. They concern how bodies are made intelligible and governable.`
    ],['feminist-philosophy','continental-philosophy','philosophy-of-mind'],['judith-butler','foucault'],['Bodies That Matter','Gender Trouble']),
    section('language-and-injury','Language, injury, and social power',[
      `Excitable Speech examines how language can injure, authorize, subordinate, and also be turned against its prior use. Hate speech and naming are not only expressions of private attitudes. They can position people within social hierarchies, mark them as vulnerable, and repeat histories of power. Butler asks how speech acts work when the authority behind them is social and historical rather than only individual.`,
      `At the same time, Butler is cautious about simple censorship solutions because speech can be resignified. Words that injure may be repeated in resistant contexts and deprived of some of their force. This does not make injury unreal. It means language is unstable enough for political struggle. The same citational structure that lets insults carry history also allows speakers to redirect inherited terms.`
    ],['philosophy-of-language','feminist-philosophy','political-philosophy'],['judith-butler','derrida','foucault'],['Excitable Speech']),
    section('recognition-and-livability','Recognition, kinship, and livable lives',[
      `Undoing Gender asks what makes a life livable under social norms. Recognition can sustain a person, but it can also require conformity to restrictive categories. People may need recognition as women, men, queer, trans, kin, parents, citizens, or mourners, while also needing those categories to become less coercive. Butler's politics therefore moves between the need for recognition and the need to transform the terms of recognition.`,
      `This tension is important for feminist and queer politics. If one rejects all categories, political organization becomes difficult. If one freezes categories, people at the margins are excluded again. Butler's work asks how movements can use categories strategically while keeping them open to revision. A livable life is not one that perfectly matches a norm, but one whose bodily and relational existence is not made impossible by norms.`
    ],['feminist-philosophy','political-philosophy','continental-philosophy'],['judith-butler','beauvoir'],['Undoing Gender']),
    section('precarity-and-assembly','Precarity, grief, and assembly',[
      `Butler's later political work emphasizes precarity, grievability, and collective assembly. Some lives are publicly mourned, protected, and represented as valuable; others are treated as threats, statistics, collateral damage, or invisible losses. This unequal distribution of grievability reveals political frames that decide whose vulnerability counts. Ethics begins from the fact that bodies are exposed to one another and dependent on social conditions.`,
      `In Notes Toward a Performative Theory of Assembly, public gathering becomes a bodily political act. People assemble not only to state demands, but to enact claims to public space, support, and existence. Bodies in the street show dependency, vulnerability, persistence, and plurality. This extends performativity from gender to collective politics: public action can make visible a people whose recognition is contested.`
    ],['political-philosophy','feminist-philosophy','continental-philosophy'],['judith-butler','arendt','foucault'],['Precarious Life','Frames of War','Notes Toward a Performative Theory of Assembly']),
    section('influence-and-controversy','Influence and fierce disagreement',[
      `Butler's influence on feminist theory, queer theory, political theory, literary studies, philosophy, and gender studies is enormous. Concepts such as performativity, heteronormativity, intelligibility, and precarious life reshaped how many fields discuss identity and power. Their work also influenced activism by giving language for understanding how norms produce exclusion and how public repetition can be disrupted.`,
      `The controversies are equally strong. Critics argue that Butler's prose is too obscure, that performativity is misused, that material reality is underplayed, or that politics needs more stable categories. Some feminist critics worry that questioning the category women weakens political solidarity. Butler's answer is that solidarity built on exclusion is unstable and unjust. The debate remains important because feminist politics needs both shared action and critical openness.`
    ],['feminist-philosophy','continental-philosophy','political-philosophy'],['judith-butler','beauvoir','foucault','derrida'],['Gender Trouble','Bodies That Matter','Undoing Gender']),
    section('misunderstandings','Common misunderstandings',[
      `The most common misunderstanding is that Butler says gender is a free choice or a mere performance in the theatrical sense. Performativity is about compelled repetition under norms, not unconstrained self-invention. Another misunderstanding is that Butler denies biological bodies. Butler argues that bodies matter, but that their social intelligibility is shaped by regulatory frameworks.`,
      `A third mistake is to treat Butler as hostile to politics because they criticize identity categories. The criticism is meant to make politics more responsive to those excluded by its own terms. A fourth misunderstanding is that difficult language is only evasion. Sometimes Butler's difficulty is excessive, but often it reflects the difficulty of asking how power operates in the categories that make ordinary clarity possible.`
    ],['feminist-philosophy','continental-philosophy'],['judith-butler'],['Gender Trouble','Bodies That Matter']),
    section('branch-connections','Butler across language, body, and politics',[
      `Butler's work crosses feminist philosophy, philosophy of language, continental philosophy, ethics, and political philosophy. Performativity begins partly from speech act theory, but it becomes a way to understand gendered embodiment. Norms are linguistic, social, bodily, institutional, and historical at once. That is why Butler cannot be reduced to either a theory of words or a theory of identity. The question is how repeated norms materialize social reality.`,
      `This branch-crossing also explains why Butler is influential beyond gender theory. The same tools used to analyze gender can illuminate hate speech, kinship, mourning, assembly, precarity, and state violence. In each case, Butler asks what frames make a subject recognizable and what forms of life remain outside recognition. The philosophical payoff is a theory of power that works before explicit law or argument, at the level of who can appear as a coherent person.`,
      `For beginners, the safest route is to keep agency and constraint together. Butler is not saying that norms are iron cages, and not saying that subjects float freely above history. A norm has power because people repeat it, institutions enforce it, and recognition depends on it. That same repetition creates openings for variation, parody, refusal, and collective demand. Politics happens in those openings.`
    ],['feminist-philosophy','philosophy-of-language','political-philosophy'],['judith-butler','foucault','derrida','beauvoir'],['Gender Trouble','Excitable Speech','Precarious Life']),
    section('reading-strategy','How to read Butler',[
      `Begin with a reliable overview of performativity, then read the preface and selected chapters of Gender Trouble. Move next to Bodies That Matter for clarification on materiality and sex. Excitable Speech is useful for language and injury, while Undoing Gender is often more accessible for recognition and livability. For political vulnerability, read Precarious Life or Notes Toward a Performative Theory of Assembly.`,
      `The guiding question should be: what norm has to be repeated for this identity or exclusion to look natural? Ask that question about gender, sex, family, speech, mourning, and public assembly. Butler becomes clearer when read as a philosopher of norms rather than as a writer of slogans. The point is not that nothing is real. The point is that reality becomes socially livable through norms that can be contested.`,
      `A good reading practice is to separate three claims that are often blurred. First, norms form subjects before deliberate choice. Second, because norms require repetition, they can be repeated differently. Third, bodies are materially vulnerable even though their social meaning is regulated. Keeping those claims apart prevents the common mistake of treating performativity as free invention. Butler is difficult because the target is difficult: power operates through the very categories that make us recognizable to ourselves and others.`
    ],['feminist-philosophy','continental-philosophy','philosophy-of-language'],['judith-butler','beauvoir','foucault','derrida'],['Gender Trouble','Bodies That Matter','Excitable Speech','Undoing Gender'])
  ],
  'angela-davis':[
    section('overview','Abolition, feminism, race, class, and collective liberation',[
      `Angela Davis is a philosopher, activist, and public intellectual whose work connects abolition, Black feminism, Marxism, prison critique, music, race, gender, class, and global solidarity. Her philosophy is not limited to academic argument, though it is deeply theoretical. It asks how institutions produce unfreedom and how movements can imagine liberation beyond reforms that leave the basic structure of domination intact.`,
      `Davis matters because she refuses single-axis analysis. Prisons cannot be understood apart from racism, capitalism, gender violence, policing, labor, and the afterlives of slavery. Feminism cannot be understood if it centers only the experiences of relatively privileged women. Freedom cannot be understood as individual success while communities remain subject to surveillance, poverty, and state violence. Davis turns social philosophy toward linked systems and collective struggle.`
    ],['feminist-philosophy','political-philosophy','continental-philosophy'],['angela-davis','marx','fanon','bell-hooks'],['Women, Race & Class','Are Prisons Obsolete?']),
    section('historical-setting','Civil rights, Black Power, prisons, and global struggle',[
      `Davis's thought emerged from the civil rights movement, Black Power, antiwar politics, Marxist organizing, feminist struggles, and campaigns against political imprisonment. The United States context includes segregation, state repression, racialized policing, economic inequality, and the growth of mass incarceration. Her work also connects these issues to global anti-colonial and socialist movements, refusing to treat American racism as an isolated domestic problem.`,
      `This setting matters because Davis writes from inside movement history. Her philosophy is shaped by organizing, imprisonment, teaching, and international solidarity. Concepts such as abolition and intersectionality are not abstract decorations. They name practical problems: how to fight institutions that present themselves as solutions while reproducing violence, and how to build movements that do not sacrifice some oppressed groups for the visibility of others.`
    ],['political-philosophy','feminist-philosophy'],['angela-davis','fanon','marx'],['Women, Race & Class','Freedom Is a Constant Struggle']),
    section('life-and-works','Scholar, activist, and public philosopher',[
      `Davis was born in Birmingham, Alabama, in 1944 and became known through scholarship, radical politics, legal persecution, imprisonment, and global campaigns for her freedom. Her education included philosophy and critical theory, and her public life brought theory into direct contact with prisons, racism, war, labor, and feminism. Reducing her to biography alone would miss the conceptual discipline of her work, but ignoring the biography would miss why the concepts carry such urgency.`,
      `Major works include Women, Race & Class, Blues Legacies and Black Feminism, Are Prisons Obsolete?, Abolition Democracy, and Freedom Is a Constant Struggle. These texts move across history, cultural analysis, political theory, and movement strategy. Davis often writes accessibly, but the accessibility should not be mistaken for simplicity. She is building a theory of freedom adequate to institutions that hide violence behind normal administration.`
    ],['feminist-philosophy','political-philosophy','ethics'],['angela-davis','marx','fanon'],['Women, Race & Class','Blues Legacies and Black Feminism','Are Prisons Obsolete?','Freedom Is a Constant Struggle']),
    section('central-question','What would freedom require beyond inclusion?',[
      `Davis's central question is what freedom would require if the institutions claiming to secure order are themselves bound up with domination. Inclusion into existing structures may matter, but it is not enough if those structures depend on racialized punishment, exploited labor, gendered violence, and economic abandonment. Freedom requires transformation of the conditions that make oppression appear normal.`,
      `This question gives abolition its philosophical force. Abolition is not only the closing of prisons or the rejection of punishment. It is a constructive project of building social relations and institutions that make cages less thinkable as solutions. Housing, education, health care, restorative practices, economic security, and community power become part of political philosophy. Davis asks readers to imagine safety without relying on organized abandonment and state violence.`
    ],['political-philosophy','feminist-philosophy','ethics'],['angela-davis','marx','fanon'],['Are Prisons Obsolete?','Abolition Democracy']),
    section('women-race-class','Women, race, and class as linked structures',[
      `Women, Race & Class challenges histories of feminism and labor that separate gender from race and class. Davis examines slavery, abolition, suffrage, domestic labor, reproductive politics, and socialist organizing to show how struggles for women's rights have sometimes excluded Black women and working-class women. The point is not to add missing names to the same story. It is to change the structure of the story.`,
      `Her analysis shows that oppression is not experienced as separate layers that can be peeled apart neatly. A Black working-class woman, for example, does not encounter racism on Monday, sexism on Tuesday, and class exploitation on Wednesday. Institutions organize these relations together. Davis's work therefore anticipates and contributes to intersectional thinking, even where she uses a Marxist and historical vocabulary rather than only the later term.`
    ],['feminist-philosophy','political-philosophy'],['angela-davis','bell-hooks','marx'],['Women, Race & Class']),
    section('abolition','Prison abolition as political imagination',[
      `Are Prisons Obsolete? asks readers to notice how recently the prison became the default answer to many social problems and how difficult it has become to imagine alternatives. Davis argues that prisons absorb the consequences of poverty, racism, mental illness, addiction, gender violence, and social abandonment while hiding those causes from view. The prison appears as a solution because the society refuses to solve the problems it cages.`,
      `Abolition, in Davis's sense, is not naive denial that harm occurs. It is a refusal to treat punitive isolation as the horizon of justice. The abolitionist question is what institutions would reduce harm, repair relations where possible, and support life without reproducing the violence they condemn. This makes abolition a deeply philosophical project: it asks what justice, responsibility, safety, and community could mean beyond retribution.`
    ],['political-philosophy','ethics'],['angela-davis','foucault'],['Are Prisons Obsolete?','Discipline and Punish']),
    section('marxism-and-capitalism','Marxism, capitalism, and racialized labor',[
      `Davis's work is deeply shaped by Marxist analysis, but she does not reduce race or gender to class in a simplistic way. She studies how capitalism, slavery, domestic labor, prisons, and racial hierarchy have been historically connected. Labor exploitation does not occur in a neutral marketplace that later receives prejudice from outside. Race and gender help organize whose labor is valued, coerced, hidden, or abandoned.`,
      `This approach lets Davis connect the plantation, the factory, the household, the prison, and the global economy without saying they are identical. Each institution has its own history, but all can participate in systems that extract value and manage populations. Her Marxism is therefore intersectional in practice: it examines material conditions while refusing to treat workers, women, prisoners, or racialized communities as homogeneous groups.`
    ],['political-philosophy','feminist-philosophy'],['angela-davis','marx','fanon'],['Women, Race & Class','Freedom Is a Constant Struggle']),
    section('culture-and-blues','Blues women and cultural philosophy',[
      `Blues Legacies and Black Feminism studies figures such as Gertrude Ma Rainey, Bessie Smith, and Billie Holiday to show how music can carry social philosophy. Davis reads blues women as articulating experiences of sexuality, labor, travel, violence, pleasure, and independence that respectability politics often suppressed. Culture becomes a site where ordinary people think, contest norms, and imagine freedom.`,
      `This work matters because it widens what counts as philosophical material. A song can reveal moral worlds, social contradictions, and forms of agency not captured by formal treatises. Davis does not romanticize culture as automatically liberating. She analyzes it historically. But she shows that Black feminist thought is not confined to academic texts. It is also present in music, performance, memory, and collective expression.`
    ],['feminist-philosophy','aesthetics','political-philosophy'],['angela-davis','bell-hooks'],['Blues Legacies and Black Feminism']),
    section('solidarity-and-movements','Solidarity, coalition, and internationalism',[
      `Davis repeatedly emphasizes solidarity across movements: anti-racist, feminist, labor, anti-prison, queer, anti-war, and anti-colonial struggles. Solidarity is not a sentimental feeling of sameness. It is a disciplined practice of seeing how struggles connect without erasing differences. This requires listening, historical study, and willingness to transform one's own movement when others expose its exclusions.`,
      `Her internationalism also matters. Davis links policing, prisons, militarism, occupation, and capitalism across national borders. This does not mean every context is identical. It means technologies of domination and resistance travel. Political philosophy, on this view, must think beyond the nation-state and beyond isolated rights claims. Freedom is collective, relational, and global in scope.`
    ],['political-philosophy','feminist-philosophy'],['angela-davis','fanon','bell-hooks'],['Freedom Is a Constant Struggle']),
    section('controversies','Radicalism, reform, and public misunderstanding',[
      `Davis's radicalism has long generated controversy. Critics often portray abolition as unrealistic, dangerous, or indifferent to victims. Davis's response is that the current system already fails victims and produces new harms. The question is not whether harm should be ignored, but whether prisons and policing actually create safety or instead manage social problems through racialized violence and disappearance.`,
      `There are also debates within abolitionist and feminist movements about strategy, violence, state power, and the relation between reform and abolition. Some reforms reduce immediate harm; others strengthen the system they seek to soften. Davis's work helps name that tension without offering an easy formula. Radical philosophy here means asking whether the deepest assumptions of public common sense are part of the problem.`
    ],['political-philosophy','ethics','feminist-philosophy'],['angela-davis','foucault','fanon'],['Are Prisons Obsolete?','Freedom Is a Constant Struggle']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is that abolition means doing nothing about harm. Davis argues for building better forms of safety, accountability, care, and prevention. Another misunderstanding is that her feminism is only about adding race to gender. Her work is more structural: race, gender, class, sexuality, and punishment are historically intertwined in institutions and movements.`,
      `A third mistake is to treat Davis as only an activist and not a philosopher. Her activism is one mode of philosophical practice, but her writings also contain sustained arguments about history, freedom, punishment, culture, and social transformation. A fourth misunderstanding is that solidarity requires identical experience. For Davis, solidarity is built through connection, study, risk, and shared struggle across difference.`
    ],['feminist-philosophy','political-philosophy'],['angela-davis'],['Women, Race & Class','Are Prisons Obsolete?']),
    section('branch-connections','Davis as social philosophy, not only policy critique',[
      `Davis belongs in political philosophy because she asks what freedom, punishment, democracy, and state power mean under racial capitalism. She belongs in feminist philosophy because she shows how gender oppression is inseparable from race, class, sexuality, and labor. She belongs in ethics because abolition asks how communities should respond to harm without reproducing harm. She also belongs in aesthetics because music and culture reveal forms of agency and resistance.`,
      `This breadth is not a loose collection of topics. It follows from the structure of the problem. Prisons are legal institutions, economic institutions, racial institutions, gendered institutions, and symbolic institutions. A theory that treats them only as criminal justice policy misses their social function. Davis's work teaches students to follow domination across categories and to ask how different institutions cooperate. That is why her philosophy is especially useful for an atlas organized by relationships rather than isolated doctrines.`,
      `Her abolitionism also changes how readers understand reform. A reform can relieve suffering in the short term and still deepen the authority of the carceral system in the long term. Davis therefore asks for strategic judgment rather than purity slogans. Which changes reduce dependence on cages, policing, and organized abandonment? Which changes merely make those systems more legitimate? That question turns abolition into a demanding form of practical reason for movements today.`
    ],['political-philosophy','feminist-philosophy','ethics'],['angela-davis','marx','fanon','bell-hooks'],['Women, Race & Class','Are Prisons Obsolete?','Blues Legacies and Black Feminism']),
    section('reading-strategy','How to read Davis',[
      `Begin with Women, Race & Class to understand her historical method and linked analysis of oppression. Then read Are Prisons Obsolete? for the abolitionist argument in a compact form. Blues Legacies and Black Feminism is essential for culture, sexuality, and Black feminist expression. Freedom Is a Constant Struggle shows her internationalism and movement orientation in a contemporary voice.`,
      `The guiding question should be: what institution is being treated as natural here, and whose unfreedom makes it work? Ask that about prisons, households, labor markets, schools, borders, and movements themselves. Davis's philosophy asks readers to move from critique to imagination. The point is not only to denounce injustice, but to build forms of life in which the old machinery of domination loses its authority.`,
      `A second reading question is: what would have to exist for this institution to become unnecessary? That question turns abolition from negation into social philosophy. If prisons are treated as answers to poverty, addiction, violence, mental illness, and abandonment, then abolition asks what housing, care, accountability, education, and economic arrangements would address those harms more directly. Davis should be read with movement history in mind because her concepts are designed for practice. They ask readers to imagine institutions that do not yet feel normal. That imagination is disciplined collective work. Practice tests the concept.`
    ],['feminist-philosophy','political-philosophy','ethics'],['angela-davis','bell-hooks','marx','fanon'],['Women, Race & Class','Are Prisons Obsolete?','Blues Legacies and Black Feminism','Freedom Is a Constant Struggle'])
  ],
  'bell-hooks':[
    section('overview','Feminism as a practice of freedom, love, and education',[
      `bell hooks is a major feminist thinker whose work connects race, gender, class, education, love, media, masculinity, spirituality, and everyday domination. She wrote in an accessible style without sacrificing theoretical force. Her feminism is not a narrow demand for individual advancement. It is a practice of freedom aimed at ending sexist oppression and the interlocking systems that sustain it.`,
      `hooks matters because she makes feminist theory answerable to ordinary life. Who gets heard in a classroom? How do children learn domination? How do racism and sexism shape desire? Why can love not flourish under domination? What does education require if students are whole persons rather than passive recipients? Her work makes philosophy intimate and public at once. It asks how power enters habits, homes, images, speech, and self-worth.`
    ],['feminist-philosophy','political-philosophy','ethics'],['bell-hooks','angela-davis','beauvoir','fanon'],['Feminist Theory: From Margin to Center','Teaching to Transgress','All About Love']),
    section('historical-setting','Black feminism, classrooms, media, and everyday power',[
      `hooks wrote in a context shaped by civil rights struggle, Black feminist thought, second-wave feminism, cultural studies, debates over representation, and the expansion of higher education. She criticized feminist movements that centered white middle-class women and ignored race, class, labor, and imperialism. She also criticized Black liberation movements when they left patriarchy intact. Her work insists that no movement for freedom can treat domination selectively.`,
      `The classroom is one of her most important settings. For hooks, education can reproduce hierarchy through silence, authority, and exclusion, or it can become a practice of freedom. Media and popular culture are equally important because they teach people how to see race, gender, beauty, desirability, and power. Philosophy, in her hands, studies the ordinary places where domination becomes common sense.`
    ],['feminist-philosophy','political-philosophy','aesthetics'],['bell-hooks','angela-davis','fanon'],['Ain\'t I a Woman','Teaching to Transgress','Black Looks']),
    section('life-and-works','Writing from the margin as a place of insight',[
      `bell hooks was the pen name of Gloria Jean Watkins, born in Kentucky in 1952. She chose the name in honor of a family member and wrote it in lowercase to direct attention toward the substance of the work rather than authorial ego. Her books range across theory, memoir, cultural criticism, pedagogy, children's writing, masculinity, love, and spirituality. The range is part of her method.`,
      `Major works include Ain't I a Woman, Feminist Theory: From Margin to Center, Talking Back, Teaching to Transgress, Black Looks, All About Love, Communion, and The Will to Change. hooks often writes in a direct voice because she wants theory to be usable. Accessibility is not simplification for its own sake. It is a political commitment to making critical language available beyond elite academic spaces.`
    ],['feminist-philosophy','ethics','political-philosophy'],['bell-hooks'],['Ain\'t I a Woman','Feminist Theory: From Margin to Center','Teaching to Transgress','Black Looks','All About Love']),
    section('central-question','How can theory help people practice freedom?',[
      `hooks's central question is how feminist theory can help people recognize, resist, and transform domination in daily life. Theory is not valuable because it sounds sophisticated. It is valuable when it names pain, clarifies structures, opens choices, and builds solidarity. For hooks, theory can be healing because it gives people language for experiences that dominant culture teaches them to accept or privatize.`,
      `This question makes her philosophy practical without making it shallow. She asks how sexism, racism, capitalism, and imperialism shape intimacy, education, work, media, and self-understanding. Freedom is not only a legal status. It is a lived capacity to think critically, love non-dominatingly, speak, listen, and build communities where people can become whole. The personal is political because power forms persons.`
    ],['feminist-philosophy','ethics','political-philosophy'],['bell-hooks','beauvoir','angela-davis'],['Feminist Theory: From Margin to Center','Teaching to Transgress']),
    section('margin-center','From margin to center',[
      `Feminist Theory: From Margin to Center argues that feminism must begin from the experiences and insights of those pushed to the margins. A feminism centered on privileged women may seek equality with privileged men while leaving racial, economic, and imperial domination intact. hooks redefines feminism as a movement to end sexist oppression, a definition that requires transformation of society rather than mere access to existing power.`,
      `The margin is not romanticized as pure virtue. It is a social location that can reveal contradictions hidden from the center. People at the margin often see both dominant culture and their own communities, which can create critical insight. Moving from margin to center means changing the questions feminism asks: not how a few women can succeed, but how domination can be dismantled for everyone.`
    ],['feminist-philosophy','political-philosophy'],['bell-hooks','angela-davis'],['Feminist Theory: From Margin to Center']),
    section('intersectional-analysis','Race, class, gender, and interlocking domination',[
      `hooks insists that sexism cannot be separated from racism, class exploitation, and imperial power. She criticized feminist writing that treated women as a homogeneous group and Black political writing that treated sexism as secondary. This does not mean every oppression is the same. It means that actual lives are shaped by systems that interact, reinforce, and sometimes mask one another.`,
      `Her analysis is especially attentive to how domination is learned emotionally and culturally. Beauty standards, romantic ideals, family roles, classroom authority, religious language, and media images all teach people what they supposedly deserve. hooks asks readers to see these patterns without despair. Naming interlocking domination is the first step toward forms of solidarity that do not ask anyone to split themselves into acceptable pieces.`
    ],['feminist-philosophy','political-philosophy','ethics'],['bell-hooks','angela-davis','fanon'],['Ain\'t I a Woman','Feminist Theory: From Margin to Center','Black Looks']),
    section('education','Teaching to transgress and engaged pedagogy',[
      `Teaching to Transgress develops hooks's vision of education as the practice of freedom. She criticizes classrooms that treat students as passive objects and teachers as disembodied authorities. Engaged pedagogy asks teachers and students to bring critical thought, experience, accountability, and whole selves into learning. The goal is not confession for its own sake. It is education that transforms perception and agency.`,
      `This view draws from Paulo Freire, Black educational traditions, feminist practice, and hooks's own classroom experience. It matters philosophically because it treats knowledge as relational and liberating. A classroom can reproduce domination through who speaks, whose experience counts, and what counts as theory. Or it can become a site where students learn to name power and imagine different forms of life.`
    ],['feminist-philosophy','ethics','political-philosophy'],['bell-hooks','martha-nussbaum'],['Teaching to Transgress']),
    section('love','Love as an ethical and political practice',[
      `All About Love argues that love should be understood as an active practice of care, knowledge, responsibility, respect, trust, and commitment. hooks rejects the idea that love is merely a feeling or romantic intensity. Love cannot coexist with domination because domination denies the full humanity of the other. This makes love an ethical concept, not a sentimental escape from politics.`,
      `Her work on love connects intimate life to social critique. Patriarchy teaches men and women distorted models of power, emotional expression, and dependency. Capitalism sells substitutes for belonging. Racism and sexism wound the capacity for trust. To practice love, then, is to resist systems that train people in domination and fear. hooks makes love philosophically serious by treating it as a discipline of freedom.`
    ],['ethics','feminist-philosophy'],['bell-hooks','martha-nussbaum'],['All About Love','The Will to Change']),
    section('masculinity-and-patriarchy','Patriarchy and the wound of masculinity',[
      `hooks writes about men and masculinity with both critique and concern. Patriarchy harms women, but it also teaches men to repress feeling, seek control, fear vulnerability, and mistake domination for strength. The Will to Change argues that feminist transformation requires addressing how boys and men are trained into emotional exile. This is not a diversion from feminism. It is part of ending sexist oppression at its roots.`,
      `Her account avoids two easy mistakes. It does not excuse male domination by saying men suffer too. Nor does it treat men as naturally incapable of love and change. Patriarchy is a system that people learn and can unlearn through accountability, care, and new forms of relation. hooks's feminism is demanding because it asks for transformation of everyone, not only empowerment of one group within the old terms.`
    ],['feminist-philosophy','ethics'],['bell-hooks','beauvoir'],['The Will to Change','Feminism Is for Everybody']),
    section('representation-and-gaze','Representation, the oppositional gaze, and cultural criticism',[
      `In Black Looks and related essays, hooks examines representation, spectatorship, and the politics of looking. The oppositional gaze names a critical way of looking developed under conditions where Black spectators, especially Black women, were denied full representation or punished for looking back. Media images are not harmless entertainment. They organize desire, fear, beauty, and social imagination.`,
      `This cultural criticism belongs in philosophy because it studies how perception is trained. Who appears as lovable, threatening, comic, intelligent, sexual, innocent, or disposable? What does a viewer learn to identify with or reject? hooks shows that domination works through images as well as laws. Critical spectatorship can become a practice of freedom when people learn to see how images are made and whom they serve.`
    ],['feminist-philosophy','aesthetics','political-philosophy'],['bell-hooks','angela-davis','fanon'],['Black Looks']),
    section('influence-and-controversy','Influence, accessibility, and criticism',[
      `hooks influenced feminist theory, Black studies, pedagogy, cultural studies, media criticism, masculinity studies, and public conversations about love. Her accessible style brought theoretical language to readers who might never enter academic philosophy. That accessibility is part of her philosophical achievement. She treated theory as a shared tool rather than a professional possession.`,
      `Some critics argue that hooks's broad range can blur distinctions among systems or that her later writing on love and spirituality moves away from structural analysis. Others see that later work as deepening the ethical conditions of liberation. The debate is useful because hooks refuses to separate institutions from inner life. She asks whether movements can survive without practices of love, education, healing, and everyday transformation.`
    ],['feminist-philosophy','political-philosophy','ethics'],['bell-hooks','angela-davis','martha-nussbaum'],['Feminist Theory: From Margin to Center','Teaching to Transgress','All About Love']),
    section('misunderstandings','Common misunderstandings',[
      `One misunderstanding is that hooks writes simply or personally because the ideas are simple. Her clarity is a political choice, not a lack of theory. Another misunderstanding is that love is a soft topic separate from power. For hooks, love names practices that domination makes difficult and that liberation requires.`,
      `A third mistake is to treat margin as an identity badge rather than a critical standpoint formed by social location and struggle. A fourth is to imagine that hooks's feminism concerns only women. She defines feminism as a movement to end sexist oppression, which means changing family, education, masculinity, media, work, and desire. Her philosophy is expansive because domination is expansive.`
    ],['feminist-philosophy','ethics','political-philosophy'],['bell-hooks'],['Feminist Theory: From Margin to Center','All About Love']),
    section('branch-connections','hooks as ethical, political, and pedagogical thinker',[
      `hooks joins ethics, political philosophy, feminist theory, aesthetics, and philosophy of education. Her account of love is ethical because it defines practices of care, respect, responsibility, and trust. It is political because domination trains people not to love well. Her account of teaching is pedagogical because it concerns classroom practice, but it is also a theory of freedom and voice. Her cultural criticism studies images as forces that shape perception.`,
      `This integration is why hooks is especially helpful for beginners. She shows that philosophy is not only a set of abstract problems stored in separate rooms. A question about media can become a question about desire; a question about desire can become a question about patriarchy; a question about patriarchy can become a question about education, race, and class. hooks teaches readers to move through those connections without losing the concreteness of everyday life.`,
      `Her method also keeps theory accountable. If a concept cannot help people recognize domination, speak more truthfully, love with less control, or teach with more freedom, hooks asks what the concept is doing. That does not make philosophy anti-intellectual. It makes intellectual work answerable to liberation.`
    ],['feminist-philosophy','ethics','aesthetics'],['bell-hooks','angela-davis','martha-nussbaum'],['Teaching to Transgress','Black Looks','All About Love']),
    section('reading-strategy','How to read bell hooks',[
      `Begin with Feminist Theory: From Margin to Center for her definition of feminism and critique of exclusion. Then read Ain't I a Woman for historical grounding in race, gender, and slavery's aftermath. Teaching to Transgress is the best entry into education and voice. Black Looks develops representation and the oppositional gaze. All About Love and The Will to Change show how ethics and intimacy belong to liberation.`,
      `The guiding question should be: where is domination being learned here? Ask it in classrooms, families, media, romance, activism, and theory itself. hooks's work is generous but unsparing. It invites readers to make philosophy usable without making it comfortable. Her legacy is a model of thought that speaks plainly because freedom should not require permission from elite language.`,
      `It helps to read hooks in two registers at once. In one register she analyzes structures: white supremacy, patriarchy, capitalism, imperialism, schooling, and media. In another she analyzes practices: listening, teaching, loving, speaking, grieving, and changing. The two registers are inseparable. Structures live through daily habits, and daily transformation needs structural critique if it is not to become private self-improvement. This is why hooks remains philosophically demanding even when the prose is open and direct.`
    ],['feminist-philosophy','political-philosophy','ethics'],['bell-hooks','angela-davis','beauvoir'],['Feminist Theory: From Margin to Center','Ain\'t I a Woman','Teaching to Transgress','Black Looks','All About Love'])
  ]
};
